def _ingest_whatsapp_plist(rag_bin: str) -> str:
    """Cross-source: WhatsApp ingester, cada 15min.

    Incremental por design — lee `messages` con `timestamp > cursor` desde la
    bridge SQLite, chunka, upsertea. En steady state con 0 mensajes nuevos el
    run termina en <1s (solo overhead de abrir la DB). Primer run full scan
    tarda ~1min por 4000 chunks (medido 2026-04-21: 12984 msgs / 65s / 4070
    chunks). Interval 900s es lo suficientemente freq para que queries tipo
    "último mensaje de X" no se sientan stale, y lo suficientemente spaced
    para no competir con watch/serve en CPU.

    `OLLAMA_KEEP_ALIVE=-1` pin's bge-m3 en VRAM para que el embed batch no
    pague cold-load en cada run. RAG_LOCAL_EMBED NO se setea (el ingester es
    bulk-embed path → ollama HTTP es el único batching-capable backend).

    `RunAtLoad=true` (2026-04-22): garantiza run inmediato al instalar o
    post-reboot; sin esto el primer refresh se demoraba hasta 15min tras
    cargar el servicio — suficiente para que "último mensaje de X" post-
    arranque del Mac devuelva data stale. El incremental cost es chico (<1s
    cuando no hay nuevos).
    """
    return f"""<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key><string>com.fer.obsidian-rag-ingest-whatsapp</string>
  <key>ProgramArguments</key>
  <array>
    <string>{rag_bin}</string>
    <string>index</string>
    <string>--source</string>
    <string>whatsapp</string>
  </array>
  <key>EnvironmentVariables</key>
  <dict>
    <key>HOME</key><string>{Path.home()}</string>
    <key>PATH</key><string>/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:{Path.home()}/.local/bin</string>
    <key>NO_COLOR</key><string>1</string>
    <key>TERM</key><string>dumb</string>
    <key>OLLAMA_KEEP_ALIVE</key><string>-1</string>
  </dict>
  <key>StartInterval</key><integer>900</integer>
  <key>RunAtLoad</key><true/>
  <key>StandardOutPath</key><string>{_RAG_LOG_DIR}/ingest-whatsapp.log</string>
  <key>StandardErrorPath</key><string>{_RAG_LOG_DIR}/ingest-whatsapp.error.log</string>
</dict>
</plist>
"""


def _ingest_gmail_plist(rag_bin: str) -> str:
    """Cross-source: Gmail ingester, cada 1h.

    Incremental via `historyId` cursor almacenado en `rag_gmail_state`. Llama
    a la API de Google Gmail así que respeta rate limits (default quota
    suficiente para 1 run/h en corpus típico ~50k emails). Cold run (bootstrap
    365d retention) puede tardar minutos; subsecuent runs son típicamente
    <30s con cero emails nuevos.

    Interval 3600s (1h) es conservative — Gmail API es cloud-hosted
    (user override §10.6 rompe local-first pero el tradeoff está documentado)
    y cada HTTP call cuesta quota. Si querés ingest más frecuente, bajar el
    interval manual y monitorear `rag log` para ver si golpeaste quota.
    """
    return f"""<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key><string>com.fer.obsidian-rag-ingest-gmail</string>
  <key>ProgramArguments</key>
  <array>
    <string>{rag_bin}</string>
    <string>index</string>
    <string>--source</string>
    <string>gmail</string>
  </array>
  <key>EnvironmentVariables</key>
  <dict>
    <key>HOME</key><string>{Path.home()}</string>
    <key>PATH</key><string>/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:{Path.home()}/.local/bin</string>
    <key>NO_COLOR</key><string>1</string>
    <key>TERM</key><string>dumb</string>
    <key>OLLAMA_KEEP_ALIVE</key><string>-1</string>
  </dict>
  <key>StartInterval</key><integer>3600</integer>
  <key>RunAtLoad</key><true/>
  <key>StandardOutPath</key><string>{_RAG_LOG_DIR}/ingest-gmail.log</string>
  <key>StandardErrorPath</key><string>{_RAG_LOG_DIR}/ingest-gmail.error.log</string>
</dict>
</plist>
"""


def _ingest_calendar_plist(rag_bin: str) -> str:
    """Cross-source: Google Calendar ingester, cada 1h.

    Incremental via `syncToken` cursor por calendar en `rag_calendar_state`.
    Google Calendar API (cloud-hosted — user override §10.6 rompe local-first).
    Bootstrap pulls 2y history + 180d future (§2.6 del design doc), subsequent
    runs son típicamente <10s (singleEvents=True expand RRULEs per instance, pero
    el delta típico es chico).

    Interval 3600s (1h) alineado con Gmail — ambos son Google OAuth cloud y
    los eventos de Calendar no cambian tan frecuentemente que valga la pena
    bajarlo. Requiere `~/.calendar-mcp/gcp-oauth.keys.json` + `credentials.json`
    (correr el OAuth flow manual antes del primer run); sin esos archivos el
    ingester silent-drops (loader retorna None).
    """
    return f"""<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key><string>com.fer.obsidian-rag-ingest-calendar</string>
  <key>ProgramArguments</key>
  <array>
    <string>{rag_bin}</string>
    <string>index</string>
    <string>--source</string>
    <string>calendar</string>
  </array>
  <key>EnvironmentVariables</key>
  <dict>
    <key>HOME</key><string>{Path.home()}</string>
    <key>PATH</key><string>/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:{Path.home()}/.local/bin</string>
    <key>NO_COLOR</key><string>1</string>
    <key>TERM</key><string>dumb</string>
    <key>OLLAMA_KEEP_ALIVE</key><string>-1</string>
  </dict>
  <key>StartInterval</key><integer>3600</integer>
  <key>RunAtLoad</key><true/>
  <key>StandardOutPath</key><string>{_RAG_LOG_DIR}/ingest-calendar.log</string>
  <key>StandardErrorPath</key><string>{_RAG_LOG_DIR}/ingest-calendar.error.log</string>
</dict>
</plist>
"""


def _ingest_reminders_plist(rag_bin: str) -> str:
    """Cross-source: Apple Reminders ingester, cada 1h.

    AppleScript full-scan (~7-100s dependiendo de cuántos reminders). Incremental
    via content-hash diff post-fetch — solo re-embedea los cambiados. En steady
    state con 0 cambios el run termina en ~7s (solo el scan sin embedding).

    Interval bajado de 6h → 1h (2026-04-22): empíricamente "37 fetched · 0
    indexados · 0 borrados · 7s" — el costo es negligible y reminders es la
    fuente MÁS dinámica en el día a día del usuario (marcar como done, crear
    nuevos). Alineado con gmail/calendar (1h) así las queries tipo "qué tengo
    esta semana" + "qué reminders pendientes" devuelven data fresh.

    `RunAtLoad=true`: corre inmediatamente al instalar / post-reboot, no hay
    que esperar 1h para ver el primer refresh.

    Local-only (EventKit via osascript); no OAuth quota. Si el AppleScript
    falla (Full Disk Access denegado, Reminders.app not running), el
    ingester silent-drops y la próxima corrida lo reintenta.
    """
    return f"""<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key><string>com.fer.obsidian-rag-ingest-reminders</string>
  <key>ProgramArguments</key>
  <array>
    <string>{rag_bin}</string>
    <string>index</string>
    <string>--source</string>
    <string>reminders</string>
  </array>
  <key>EnvironmentVariables</key>
  <dict>
    <key>HOME</key><string>{Path.home()}</string>
    <key>PATH</key><string>/opt/homebrew/bin:/usr/local/bin:/usr/bin:/bin:{Path.home()}/.local/bin</string>
    <key>NO_COLOR</key><string>1</string>
    <key>TERM</key><string>dumb</string>
    <key>OLLAMA_KEEP_ALIVE</key><string>-1</string>
  </dict>
  <key>StartInterval</key><integer>3600</integer>
  <key>RunAtLoad</key><true/>
  <key>StandardOutPath</key><string>{_RAG_LOG_DIR}/ingest-reminders.log</string>
  <key>StandardErrorPath</key><string>{_RAG_LOG_DIR}/ingest-reminders.error.log</string>
</dict>
</plist>
"""


def _services_spec(rag_bin: str) -> list[tuple[str, str, str]]:
    """Return [(label, plist_filename, plist_xml), ...]."""
    return [
        ("com.fer.obsidian-rag-watch", "com.fer.obsidian-rag-watch.plist",
         _watch_plist(rag_bin)),
        ("com.fer.obsidian-rag-serve", "com.fer.obsidian-rag-serve.plist",
         _serve_plist(rag_bin)),
        # Web UI daemon — previously installed manually outside `rag setup`
        # (Apr 2026), which left HF_HUB_OFFLINE + RAG_MEMORY_PRESSURE_INTERVAL
        # missing in the actual plist and produced 64× [local-embed] falls +
        # 23× MPS Metal OOMs. Now generated from source.
        ("com.fer.obsidian-rag-web", "com.fer.obsidian-rag-web.plist",
         _web_plist(rag_bin)),
        ("com.fer.obsidian-rag-digest", "com.fer.obsidian-rag-digest.plist",
         _digest_plist(rag_bin)),
        ("com.fer.obsidian-rag-morning", "com.fer.obsidian-rag-morning.plist",
         _morning_plist(rag_bin)),
        ("com.fer.obsidian-rag-today", "com.fer.obsidian-rag-today.plist",
         _today_plist(rag_bin)),
        ("com.fer.obsidian-rag-emergent", "com.fer.obsidian-rag-emergent.plist",
         _emergent_plist(rag_bin)),
        ("com.fer.obsidian-rag-patterns", "com.fer.obsidian-rag-patterns.plist",
         _patterns_plist(rag_bin)),
        ("com.fer.obsidian-rag-archive", "com.fer.obsidian-rag-archive.plist",
         _archive_plist(rag_bin)),
        ("com.fer.obsidian-rag-wa-tasks", "com.fer.obsidian-rag-wa-tasks.plist",
         _wa_tasks_plist(rag_bin)),
        ("com.fer.obsidian-rag-online-tune", "com.fer.obsidian-rag-online-tune.plist",
         _online_tune_plist(rag_bin)),
        ("com.fer.obsidian-rag-maintenance", "com.fer.obsidian-rag-maintenance.plist",
         _maintenance_plist(rag_bin)),
        ("com.fer.obsidian-rag-consolidate", "com.fer.obsidian-rag-consolidate.plist",
         _consolidate_plist(rag_bin)),
        # Cross-source ingesters (2026-04-21) — Phase 1.a-1.d ya implementados
        # en código; estos plists los ponen en loop para que el corpus
        # cross-source esté fresh sin intervención manual. Calendar se skipea
        # al install si `~/.calendar-mcp/credentials.json` no existe — el
        # usuario corre el OAuth flow primero (ver docstring de
        # `_ingest_calendar_plist`), después re-corre `rag setup`.
        ("com.fer.obsidian-rag-ingest-whatsapp",
         "com.fer.obsidian-rag-ingest-whatsapp.plist",
         _ingest_whatsapp_plist(rag_bin)),
        ("com.fer.obsidian-rag-ingest-gmail",
         "com.fer.obsidian-rag-ingest-gmail.plist",
         _ingest_gmail_plist(rag_bin)),
        ("com.fer.obsidian-rag-ingest-reminders",
         "com.fer.obsidian-rag-ingest-reminders.plist",
         _ingest_reminders_plist(rag_bin)),
        ("com.fer.obsidian-rag-ingest-calendar",
         "com.fer.obsidian-rag-ingest-calendar.plist",
         _ingest_calendar_plist(rag_bin)),
    ]


@cli.command()
@click.option("--remove", is_flag=True,
              help="Desinstalar los servicios en lugar de instalarlos")
def setup(remove: bool):
    """Instalar (o desinstalar) los servicios launchd que mantienen el RAG vivo
    sin intervención: `rag watch` (auto-reindex) y `rag digest` (semanal).
    Idempotente — re-correr lo recarga.
    """
    import subprocess
    rag_bin = _rag_binary()
    if not Path(rag_bin).is_file():
        console.print(f"[red]No encuentro el binario `rag`:[/red] {rag_bin}")
        console.print("[dim]Instalá primero: uv tool install --reinstall --editable .[/dim]")
        return
    _LAUNCH_AGENTS_DIR.mkdir(parents=True, exist_ok=True)
    _RAG_LOG_DIR.mkdir(parents=True, exist_ok=True)

    for label, fname, content in _services_spec(rag_bin):
        plist_path = _LAUNCH_AGENTS_DIR / fname
        # Always unload first so a stale version doesn't linger after reinstall.
        if plist_path.exists():
            subprocess.run(
                ["launchctl", "unload", str(plist_path)],
                check=False, capture_output=True,
            )
        if remove:
            if plist_path.exists():
                plist_path.unlink()
                console.print(f"[green]✓[/green] removido: {label}")
            else:
                console.print(f"[dim]· no estaba instalado: {label}[/dim]")
            continue
        # Calendar gate: sin OAuth config, instalar el plist sólo loggearía
        # errors cada hora. Skipear con nota — el user re-corre `rag setup`
        # tras el OAuth flow.
        if label == "com.fer.obsidian-rag-ingest-calendar":
            cal_creds = Path.home() / ".calendar-mcp" / "credentials.json"
            if not cal_creds.is_file():
                console.print(
                    f"[yellow]·[/yellow] skip {label}: falta "
                    f"[dim]~/.calendar-mcp/credentials.json[/dim] "
                    f"(correr OAuth flow primero)"
                )
                continue
        plist_path.write_text(content, encoding="utf-8")
        try:
            subprocess.run(
                ["launchctl", "load", str(plist_path)],
                check=True, capture_output=True,
            )
            console.print(f"[green]✓[/green] cargado: [bold]{label}[/bold]")
        except subprocess.CalledProcessError as e:
            stderr = e.stderr.decode(errors="ignore") if e.stderr else ""
            console.print(f"[red]✗[/red] falló cargar {label}: {stderr.strip()}")

    if not remove:
        # Pre-build Apple Contacts disk cache. La primera invocación del
        # resolver `_resolve_sender_to_name` dispara `_load_contacts_phone_index()`
        # que dumpea el address book completo via osascript — ~85s para ~350
        # contactos en el host del autor. Si `rag setup` no lo calienta, ese
        # costo lo paga la primera query cross-source post-install (suele ser
        # `rag serve` handling un WA inbound). Pre-buildearlo acá mueve el
        # hit al setup, donde el user ya está esperando.
        #
        # Silent-fail: si Contacts.app está restringido o el dump falla, el
        # resolver degrada al mask fallback (`…XXXX`) — no bloquea el setup.
        # Solo corre si el cache en disk no existe o expiró (TTL 24h).
        try:
            cache_path = _CONTACTS_PHONE_INDEX_PATH
            cache_stale = (
                not cache_path.is_file()
                or (time.time() - cache_path.stat().st_mtime) > _CONTACTS_PHONE_INDEX_TTL_S
            )
            if cache_stale:
                console.print()
                console.print(
                    "[dim]Pre-building Apple Contacts phone index "
                    "(primer run, ~1-2min)…[/dim]"
                )
                t0 = time.time()
                idx = _load_contacts_phone_index()
                if idx:
                    console.print(
                        f"[green]✓[/green] contacts cache: "
                        f"{len(idx)} phones indexados en {time.time()-t0:.1f}s"
                    )
                else:
                    console.print(
                        "[yellow]·[/yellow] contacts cache vacío "
                        "(Contacts.app no accesible o sin teléfonos) — "
                        "el resolver usa mask fallback"
                    )
        except Exception as exc:
            _silent_log("setup_contacts_warmup", exc)
            console.print(
                "[yellow]·[/yellow] contacts cache warmup falló — continuá sin ello"
            )

        console.print()
        console.print(
            f"[dim]Logs en {_RAG_LOG_DIR}/{{watch,digest,morning,today,emergent,patterns,archive,"
            f"wa-tasks,online-tune,consolidate,ingest-whatsapp,ingest-gmail,ingest-reminders}}"
            f".{{log,error.log}}[/dim]"
        )


@cli.group()
def ambient():
    """Ambient Agent: reacciona a capturas en 00-Inbox con wikilinks+dupes+related."""


@ambient.command("status")
def ambient_status():
    """¿Está habilitado? ¿A qué jid manda?"""
    cfg = _ambient_config()
    if cfg is None:
        if not AMBIENT_CONFIG_PATH.is_file():
            console.print("[yellow]Deshabilitado[/yellow] — no hay config. Enviá /enable_ambient al bot de WhatsApp.")
        else:
            # Detectar schema viejo para dar un hint útil.
            try:
                raw = json.loads(AMBIENT_CONFIG_PATH.read_text(encoding="utf-8"))
            except Exception:
                raw = {}
            if raw.get("chat_id") or raw.get("bot_token"):
                console.print(
                    "[yellow]Deshabilitado[/yellow] — config tiene schema viejo "
                    "(chat_id/bot_token del bot anterior). Re-habilitá con "
                    "/enable_ambient en el bot de WhatsApp."
                )
            else:
                console.print(
                    "[yellow]Deshabilitado[/yellow] — config existe pero está mal "
                    "o tiene enabled=false."
                )
        return
    console.print(
        f"[green]Habilitado[/green] · jid=[cyan]{cfg['jid']}[/cyan]"
    )
    if AMBIENT_STATE_PATH.is_file():
        try:
            n = sum(1 for _ in AMBIENT_STATE_PATH.open())
            console.print(f"[dim]State: {n} análisis registrados[/dim]")
        except Exception:
            pass


@ambient.command("disable")
def ambient_disable():
    """Deshabilitar ambient (deja el config pero con enabled=false)."""
    if not AMBIENT_CONFIG_PATH.is_file():
        console.print("[dim]No había config.[/dim]")
        return
    try:
        c = json.loads(AMBIENT_CONFIG_PATH.read_text(encoding="utf-8"))
    except Exception:
        c = {}
    c["enabled"] = False
    AMBIENT_CONFIG_PATH.write_text(json.dumps(c, indent=2), encoding="utf-8")
    console.print("[green]✓[/green] ambient deshabilitado. Re-habilitar con /enable_ambient en el bot.")


@ambient.command("test")
@click.argument("path", required=False)
def ambient_test(path: str | None):
    """Simular análisis sobre una nota existente (dry-run en vivo, sí escribe)."""
    col = get_db()
    if path is None:
        inbox = VAULT_PATH / _CAPTURE_FOLDER
        candidates = sorted(inbox.glob("*.md"))[:1]
        if not candidates:
            console.print(f"[yellow]Sin notas en {inbox}[/yellow]")
            return
        p = candidates[0]
    else:
        p = VAULT_PATH / path if not path.startswith("/") else Path(path)
    if not p.is_file():
        console.print(f"[red]No existe:[/red] {p}")
        return
    doc_id_prefix = str(p.relative_to(VAULT_PATH))
    raw = p.read_text(encoding="utf-8", errors="ignore")
    h = file_hash(raw)
    console.print(f"[cyan]Triggereando ambient hook sobre:[/cyan] {doc_id_prefix}")
    _ambient_hook(col, p, doc_id_prefix, h)
    console.print("[green]✓[/green] Listo. Ver log: tail ~/.local/share/obsidian-rag/ambient.jsonl")


def _load_raw_ambient_config() -> dict:
    """Read raw ambient config JSON (no filtering). Empty dict if missing."""
    if not AMBIENT_CONFIG_PATH.is_file():
        return {}
    try:
        c = json.loads(AMBIENT_CONFIG_PATH.read_text(encoding="utf-8"))
        return c if isinstance(c, dict) else {}
    except Exception:
        return {}


def _save_raw_ambient_config(cfg: dict) -> None:
    """Atomic-ish write of the raw ambient config. Preserves other keys."""
    AMBIENT_CONFIG_PATH.parent.mkdir(parents=True, exist_ok=True)
    AMBIENT_CONFIG_PATH.write_text(
        json.dumps(cfg, indent=2, ensure_ascii=False), encoding="utf-8"
    )


@ambient.group("folders")
def ambient_folders():
    """Administrar carpetas donde corre el hook ambient (default 00-Inbox)."""


@ambient_folders.command("list")
def ambient_folders_list():
    """Listar allowed_folders actuales."""
    cfg = _load_raw_ambient_config()
    folders = cfg.get("allowed_folders") or []
    if not folders:
        console.print(
            f"[dim]Default:[/dim] [cyan]{_CAPTURE_FOLDER}[/cyan] "
            "[dim](no hay allowed_folders seteado)[/dim]"
        )
        return
    console.print("[cyan]Ambient corre sobre:[/cyan]")
    for f in folders:
        console.print(f"  · [cyan]{f}[/cyan]")


@ambient_folders.command("add")
@click.argument("folder")
def ambient_folders_add(folder: str):
    """Agregar una carpeta del vault a allowed_folders (dedup + valida)."""
    folder = folder.rstrip("/").strip()
    if not folder:
        console.print("[red]Folder vacío.[/red]")
        return
    target = VAULT_PATH / folder
    if not target.is_dir():
        console.print(
            f"[red]No existe en el vault:[/red] {target}"
        )
        return
    cfg = _load_raw_ambient_config()
    if not cfg:
        console.print(
            "[yellow]No hay ambient config[/yellow] — enviá /enable_ambient "
            "al bot de WhatsApp primero."
        )
        return
    folders = list(cfg.get("allowed_folders") or [])
    if folder in folders:
        console.print(f"[dim]Ya estaba:[/dim] {folder}")
        return
    folders.append(folder)
    cfg["allowed_folders"] = folders
    _save_raw_ambient_config(cfg)
    console.print(f"[green]✓[/green] Agregado [cyan]{folder}[/cyan]")
    console.print(f"[dim]Ahora:[/dim] {', '.join(folders)}")


@ambient_folders.command("remove")
@click.argument("folder")
def ambient_folders_remove(folder: str):
    """Quitar carpeta. Si queda vacía → vuelve a default [00-Inbox]."""
    folder = folder.rstrip("/").strip()
    cfg = _load_raw_ambient_config()
    if not cfg:
        console.print("[yellow]No hay ambient config.[/yellow]")
        return
    folders = list(cfg.get("allowed_folders") or [])
    if folder not in folders:
        console.print(f"[dim]No estaba:[/dim] {folder}")
        return
    folders = [f for f in folders if f != folder]
    if not folders:
        # Wipe the field → the config reader falls back to default.
        cfg.pop("allowed_folders", None)
        _save_raw_ambient_config(cfg)
        console.print(
            f"[green]✓[/green] Quitado {folder}. Default restaurado: "
            f"[cyan]{_CAPTURE_FOLDER}[/cyan]"
        )
        return
    cfg["allowed_folders"] = folders
    _save_raw_ambient_config(cfg)
    console.print(f"[green]✓[/green] Quitado [cyan]{folder}[/cyan]")
    console.print(f"[dim]Ahora:[/dim] {', '.join(folders)}")


@ambient.command("log")
@click.option("-n", default=10, show_default=True, help="Últimos N eventos")
def ambient_log(n: int):
    """Tail del log de eventos ambient."""
    if not AMBIENT_LOG_PATH.is_file():
        console.print(f"[yellow]Aún no hay log en {AMBIENT_LOG_PATH}[/yellow]")
        return
    lines = AMBIENT_LOG_PATH.read_text(encoding="utf-8").splitlines()[-n:]
    for line in lines:
        try:
            e = json.loads(line)
        except Exception:
            continue
        ts = e.get("ts", "")[-8:]
        applied = e.get("wikilinks_applied", 0)
        dupes = len(e.get("dupes") or [])
        rel = e.get("related_count", 0)
        sent = "📨" if e.get("whatsapp_sent") else ("🔇" if e.get("quiet") else "✗")
        console.print(
            f"[dim]{ts}[/dim] {sent} "
            f"[cyan]{e.get('path', '—')}[/cyan] "
            f"[yellow]links={applied}[/yellow] "
            f"[magenta]dupes={dupes}[/magenta] "
            f"[blue]rel={rel}[/blue]"
        )


# ── Tasks-mode: intent + time-scope for WhatsApp/web/CLI agenda queries ─────
# When the user asks "qué tengo que hacer esta semana" the right answer is not
# a vault RAG retrieve (that picks up recent WA markdown and answers with a
# chat fragment) — it's the live services layer filtered to the right window.
# Helpers here are consumed by `rag serve` `/query` and by `web/server.py`.

_TASKS_INTENT_TOKENS = re.compile(
    r"\b(pendientes?|agenda|recordatorios?|to-?dos?|tasks?|reminders?|"
    r"tareas?|reuniones?|meetings?|prioridad(?:es)?|prioriz|"
    r"compromisos?|obligaciones?|deberes?)",
    re.IGNORECASE,
)
_TASKS_INTENT_PHRASES = re.compile(
    r"(qu[eé]\s+(tengo|hacer|debo|hay|me\s+falta|me\s+queda)|"
    r"what\s+do\s+i\s+(have|need)|"
    r"(tengo|hay)\s+(algo|cosas?|eventos?|citas?)\s+(pendiente|hoy|mañana|esta\s+semana)|"
    r"que\s+hay\s+(para\s+)?(hoy|mañana|esta\s+semana)|"
    r"organiz(ar|ame)\s+(el\s+d[ií]a|la\s+semana))",
    re.IGNORECASE,
)


def _is_tasks_query(q: str) -> bool:
    if not q:
        return False
    return bool(_TASKS_INTENT_TOKENS.search(q) or _TASKS_INTENT_PHRASES.search(q))


_SCOPE_N_DAYS = re.compile(
    r"\bpr[oó]xim[oa]s?\s+(\d+)\s+d[ií]as?\b|\bnext\s+(\d+)\s+days?\b",
    re.IGNORECASE,
)
_SCOPE_WEEK = re.compile(
    r"\besta\s+semana\b|\bpr[oó]xima\s+semana\b|\bsemana\s+que\s+viene\b|"
    r"\bthis\s+week\b|\bnext\s+week\b",
    re.IGNORECASE,
)
_SCOPE_TOMORROW = re.compile(r"\bma(?:ñ|n)ana\b|\btomorrow\b", re.IGNORECASE)
_SCOPE_TODAY = re.compile(
    r"\bhoy\b|\bahora\b|\btoday\b|\beste\s+momento\b", re.IGNORECASE,
)


def _detect_time_scope(q: str) -> dict:
    """Return the time scope carried by the query. Priority: explicit N days
    beats week beats tomorrow beats today; unmarked queries get a 14-day
    reminders window + 7-day calendar window.
    """
    m = _SCOPE_N_DAYS.search(q or "")
    if m:
        n = int(m.group(1) or m.group(2) or 0)
        n = max(1, min(30, n))
        return {
            "key": "n_days", "label": f"próximos {n} días",
            "reminders_horizon": n + 1, "calendar_ahead": n,
        }
    if _SCOPE_WEEK.search(q or ""):
        return {
            "key": "week", "label": "esta semana",
            "reminders_horizon": 8, "calendar_ahead": 7,
        }
    if _SCOPE_TOMORROW.search(q or ""):
        return {
            "key": "tomorrow", "label": "mañana",
            "reminders_horizon": 2, "calendar_ahead": 1,
        }
    if _SCOPE_TODAY.search(q or ""):
        return {
            "key": "today", "label": "hoy",
            "reminders_horizon": 1, "calendar_ahead": 0,
        }
    return {
        "key": "general", "label": "próximas 2 semanas",
        "reminders_horizon": 14, "calendar_ahead": 7,
    }


def _fetch_calendar_ahead(days_ahead: int, max_events: int = 40) -> list[dict]:
    """icalBuddy `eventsToday+N` with relative-date labels. Returns
    [{title, date_label, time_range}]. Silent-fail per contract."""
    if not _apple_enabled() or days_ahead < 0:
        return []
    icb = _icalbuddy_path()
    if not icb:
        return []
    import subprocess as _sp
    query = "eventsToday" if days_ahead == 0 else f"eventsToday+{days_ahead}"
    try:
        res = _sp.run(
            [icb, "-nc", "-iep", "title,datetime", "-b", "", query],
            capture_output=True, text=True, timeout=10.0,
        )
    except (FileNotFoundError, _sp.TimeoutExpired, OSError):
        return []
    if res.returncode != 0 or not (res.stdout or "").strip():
        return []
    events: list[dict] = []
    current: dict | None = None
    for raw in (res.stdout or "").splitlines():
        line = raw.rstrip()
        if not line:
            continue
        if not line.startswith(" ") and not line.startswith("\t"):
            if current and current.get("title"):
                events.append(current)
            current = {"title": line.strip(), "date_label": "", "time_range": ""}
            continue
        stripped = line.strip()
        if current is None:
            continue
        m = re.search(
            r"(\d{1,2}:\d{2}(?:\s*[AaPp][Mm])?)\s*-\s*(\d{1,2}:\d{2}(?:\s*[AaPp][Mm])?)",
            stripped,
        )
        if m:
            current["time_range"] = f"{m.group(1)}–{m.group(2)}"
            label = stripped.split(" at ", 1)[0].strip()
            if label and label != stripped:
                current["date_label"] = label
        else:
            current["date_label"] = stripped
    if current and current.get("title"):
        events.append(current)
    return events[:max_events]


# ── Cross-source enrichment for web chat ─────────────────────────────────
# After a chat answer streams to the user, run a fast entity extraction +
# parallel scan of WhatsApp/Calendar/Reminders so the UI can show a
# "📎 contexto relacionado" footer with cross-channel signals (e.g.
# "📅 esta reunión ya está en tu calendar mañana 15hs").
# Wall budget: ~1.5s. Soft-fail per source — never block the answer.

_ENRICH_HELPER_PROMPT = (
    "Extraé entidades mencionadas en la respuesta sobre las notas del usuario. "
    "Devolvé SOLO JSON con esta forma exacta: "
    '{"people":[],"events":[],"topics":[]}. '
    "people: nombres propios de personas (sin títulos). "
    "events: reuniones, viajes, llamadas, deadlines. "
    "topics: 1-3 temas principales. "
    "Cada lista vacía si no hay nada. NADA fuera del JSON."
)


def extract_enrich_entities(question: str, answer: str) -> dict:
    """Single helper-LLM pass to mine names/events/topics from the answer.
    Used by build_enrich_payload to feed cross-source lookups.
    Returns {"people": [...], "events": [...], "topics": [...]}.
    Skipped (returns empty) for very short answers or on any error.
    """
    empty = {"people": [], "events": [], "topics": []}
    if not answer or len(answer.strip()) < 40:
        return empty
    user_msg = f"Pregunta: {question}\n\nRespuesta:\n{answer[:1500]}"
    # Reuse the resident chat model (qwen2.5:7b, already pinned via the
    # web prewarmer) instead of qwen2.5:3b — avoids the 2-5s cold load
    # that blew the enrich budget repeatedly. JSON-mode + 160 tokens lands
    # at ~600-900ms warm, well inside the wall ceiling.
    try:
        rsp = ollama.chat(
            model=resolve_chat_model(),
            messages=[
                {"role": "system", "content": _ENRICH_HELPER_PROMPT},
                {"role": "user", "content": user_msg},
            ],
            options={**CHAT_OPTIONS, "num_predict": 160, "num_ctx": 2048, "format": "json"},
            keep_alive=chat_keep_alive(),
        )
        raw = (rsp.message.content or "").strip()
        data = json.loads(raw)
        return {
            "people": [str(p).strip() for p in (data.get("people") or []) if str(p).strip()][:5],
            "events": [str(e).strip() for e in (data.get("events") or []) if str(e).strip()][:5],
            "topics": [str(t).strip() for t in (data.get("topics") or []) if str(t).strip()][:5],
        }
    except Exception:
        return empty


def _humanize_relative_es(ts_str: str) -> str:
    """ISO/SQLite timestamp → 'hoy' / 'ayer' / 'hace 3 días' / 'hace 2 semanas'.
    Handles both 'YYYY-MM-DD HH:MM:SS±HH:MM' (WA SQLite) and ISO-8601.
    """
    if not ts_str:
        return ""
    try:
        s = ts_str.replace("Z", "+00:00")
        if " " in s and "T" not in s:
            s = s.replace(" ", "T", 1)
        dt = datetime.fromisoformat(s)
        # Drop tz so we can subtract from naive datetime.now()
        if dt.tzinfo is not None:
            dt = dt.replace(tzinfo=None)
    except (ValueError, TypeError):
        return ""
    delta = datetime.now() - dt
    if delta.days < 0:
        return ""
    if delta.days == 0:
        return "hoy"
    if delta.days == 1:
        return "ayer"
    if delta.days < 7:
        return f"hace {delta.days} días"
    weeks = delta.days // 7
    return f"hace {weeks} semana{'s' if weeks > 1 else ''}"


def _enrich_terms(entities: dict, min_len: int = 3) -> list[str]:
    raw = entities.get("people", []) + entities.get("events", []) + entities.get("topics", [])
    out: list[str] = []
    seen: set[str] = set()
    for t in raw:
        k = (t or "").strip().lower()
        if len(k) < min_len or k in seen:
            continue
        seen.add(k)
        out.append(t)
    return out


_CONTACT_NAME_CACHE: dict[str, str] = {}


def _apple_contact_name(phone: str) -> str | None:
    """Look up a phone number in macOS Contacts via osascript. Returns the
    contact's name or None. Cached in-process — Contacts isn't going to
    change mid-process and osascript is ~200ms per call. `phone` is
    normalised to digits-only before query (Contacts stores formatted
    numbers, the `whose ... contains` predicate matches substrings).
    """
    if not _apple_enabled() or not phone:
        return None
    digits = "".join(ch for ch in phone if ch.isdigit())
    if len(digits) < 8:
        return None
    if digits in _CONTACT_NAME_CACHE:
        return _CONTACT_NAME_CACHE[digits] or None
    import subprocess
    script = (
        'tell application "Contacts" to '
        'set _ppl to (every person whose value of phones contains "' + digits + '")\n'
        'if (count of _ppl) is 0 then return ""\n'
        'return name of (item 1 of _ppl)'
    )
    try:
        res = subprocess.run(
            ["osascript", "-e", script],
            capture_output=True, text=True, timeout=3,
        )
        name = (res.stdout or "").strip()
    except Exception:
        name = ""
    _CONTACT_NAME_CACHE[digits] = name
    return name or None


def _enrich_wa(entities: dict, days: int = 7, max_hits: int = 2) -> list[dict]:
    """Recent WhatsApp messages mentioning any entity term. SQLite read-only."""
    terms = _enrich_terms(entities)
    if not terms or not WHATSAPP_DB_PATH.is_file():
        return []
    import sqlite3
    cutoff = (datetime.now() - timedelta(days=days)).isoformat(sep=" ", timespec="seconds")
    like_clauses = " OR ".join(["LOWER(content) LIKE ?"] * len(terms))
    params: list = [cutoff] + [f"%{t.lower()}%" for t in terms]
    sql = f"""
      SELECT m.chat_jid, m.content, m.timestamp,
             COALESCE(c.name, m.chat_jid) AS chat_name
      FROM messages m
      LEFT JOIN chats c ON c.jid = m.chat_jid
      WHERE m.timestamp > ? AND m.content IS NOT NULL AND m.content != ''
        AND ({like_clauses})
      ORDER BY m.timestamp DESC
      LIMIT 50
    """
    try:
        con = sqlite3.connect(f"file:{WHATSAPP_DB_PATH}?mode=ro&immutable=1", uri=True)
        rows = list(con.execute(sql, params))
        con.close()
    except sqlite3.Error:
        return []
    seen_chats: set[str] = set()
    hits: list[dict] = []
    for jid, content, ts, chat_name in rows:
        if jid in seen_chats:
            continue
        seen_chats.add(jid)
        snippet = (content or "").replace("\n", " ").strip()[:80]
        # Pretty label: prefer chat name; fall back to phone (DM) or "grupo"
        is_group = jid.endswith("@g.us")
        is_lid = jid.endswith("@lid")  # WhatsApp opaque privacy identifier
        bare_name = (chat_name or "").strip()
        # chat_name often falls back to the bare jid (just digits) when the
        # contact wasn't synced — try Apple Contacts before falling back to
        # the raw phone (and skip the +<digits> fallback for @lid which is
        # a privacy identifier, not a real phone).
        if not bare_name or bare_name == jid or bare_name.isdigit() or bare_name == jid.split("@")[0]:
            phone = jid.split("@")[0]
            resolved = None
            if phone.isdigit() and not is_lid:
                resolved = _apple_contact_name(phone)
            if resolved:
                bare_name = resolved
            elif is_lid:
                bare_name = "contacto sin nombre"
            else:
                bare_name = (f"+{phone}" if phone.isdigit() else phone) or "WhatsApp"
        chat_label = f"grupo «{bare_name}»" if is_group else bare_name
        hits.append({
            "icon": "💬",
            "text": f"hablaste en {chat_label}",
            "snippet": snippet,
            "relative": _humanize_relative_es(ts),
            "channel": "wa",
        })
        if len(hits) >= max_hits:
            break
    return hits


def _enrich_calendar(entities: dict, max_hits: int = 2) -> list[dict]:
    """Calendar events whose title matches an entity term."""
    terms = [t.lower() for t in _enrich_terms(entities)]
    if not terms:
        return []
    today = _fetch_calendar_today(max_events=15)
    ahead = _fetch_calendar_ahead(days_ahead=7, max_events=40)
    seen: set[str] = set()
    hits: list[dict] = []
    for ev in today + ahead:
        title = (ev.get("title") or "").strip()
        title_l = title.lower()
        if not title or title_l in seen:
            continue
        if not any(t in title_l for t in terms):
            continue
        seen.add(title_l)
        when = ev.get("start") or ev.get("date_label") or ""
        time_range = ev.get("time_range") or ""
        when_label = " ".join(p for p in [when, time_range] if p).strip()
        hits.append({
            "icon": "📅",
            "text": f"está en tu calendar: «{title}»",
            "snippet": when_label,
            "relative": "",
            "channel": "calendar",
        })
        if len(hits) >= max_hits:
            break
    return hits


def _enrich_reminders(entities: dict, max_hits: int = 2) -> list[dict]:
    """Reminders whose name matches an entity term."""
    terms = [t.lower() for t in _enrich_terms(entities)]
    if not terms:
        return []
    items = _fetch_reminders_due(datetime.now(), horizon_days=14, max_items=40)
    bucket_label = {"overdue": "vencido", "today": "hoy", "upcoming": "próximo", "undated": "sin fecha"}
    hits: list[dict] = []
    for it in items:
        name = (it.get("name") or "").strip()
        if not any(t in name.lower() for t in terms):
            continue
        hits.append({
            "icon": "✓",
            "text": f"reminder relacionado: «{name}»",
            "snippet": bucket_label.get(it.get("bucket", ""), ""),
            "relative": "",
            "channel": "reminders",
        })
        if len(hits) >= max_hits:
            break
    return hits


def build_enrich_payload(question: str, answer: str, top_score: float) -> dict | None:
    """Compose the cross-source enrichment block for the web chat footer.

    Pipeline: extract entities → fan out to WA/Calendar/Reminders → merge,
    cap to 5 lines, prioritise Calendar > Reminders > WA. Returns
    `{"lines": [...], "entities": {...}}` or None when nothing surfaces.
    Skipped on short answers or low-confidence retrieval.
    """
    if not answer or len(answer.strip()) < 40:
        return None
    if top_score < CONFIDENCE_RERANK_MIN:
        return None
    entities = extract_enrich_entities(question, answer)
    if not (entities["people"] or entities["events"] or entities["topics"]):
        return None
    cal = _enrich_calendar(entities) if _apple_enabled() else []
    rem = _enrich_reminders(entities) if _apple_enabled() else []
    wa = _enrich_wa(entities)
    lines = (cal + rem + wa)[:5]
    if not lines:
        return None
    return {"lines": lines, "entities": entities}


def _collect_scoped_tasks_evidence(col, now: datetime, scope: dict) -> dict:
    """`_pendientes_collect` under the hood, then override `reminders` and
    `calendar_range` with scope-aware fetches. Ensures `whatsapp` always
    populated even if the base collector skipped silently.

    Single-vault version kept for callers that pass a sqlite-vec collection
    directly (rag morning/today still use this). Multi-vault tasks-mode
    uses `_collect_scoped_tasks_evidence_multi` instead.

    Reminders / Calendar / WhatsApp fetchers run in parallel — each is an
    independent IPC round-trip (osascript / icalBuddy / sqlite) so serial
    execution wasted wall-clock for no gain. Silent-fail contract preserved
    per-future.
    """
    from concurrent.futures import ThreadPoolExecutor
    ev = _pendientes_collect(col, now, days=14)

    def _reminders():
        try:
            return _fetch_reminders_due(
                now, horizon_days=int(scope["reminders_horizon"]), max_items=40,
            )
        except Exception:
            return None

    def _calendar():
        try:
            return _fetch_calendar_ahead(int(scope["calendar_ahead"]))
        except Exception:
            return None

    def _whatsapp():
        try:
            return _fetch_whatsapp_unread(hours=24, max_chats=8)
        except Exception:
            return None

    with ThreadPoolExecutor(max_workers=3) as ex:
        f_rem = ex.submit(_reminders)
        f_cal = ex.submit(_calendar)
        f_wa = ex.submit(_whatsapp) if not ev.get("whatsapp") else None
        rem = f_rem.result()
        cal = f_cal.result()
        wa = f_wa.result() if f_wa else None
    if rem is not None:
        ev["reminders"] = rem
    if cal is not None:
        ev["calendar_range"] = cal
    if wa is not None:
        ev["whatsapp"] = wa
    return ev


def _collect_scoped_tasks_evidence_multi(
    vaults: list[tuple[str, Path]], now: datetime, scope: dict,
) -> dict:
    """Multi-vault tasks evidence: system services fetched once (Reminders,
    Calendar, Gmail, Apple Mail, WhatsApp — none of these are vault-scoped),
    vault loops + contradictions aggregated per-vault with `_vault` label.

    The user asked for both personal (`home`) and work (`work`) vaults to
    surface their open loops in the tasks-mode answer. Without this, the
    work vault's pending items were invisible on WhatsApp/web queries.

    All 6 system fetchers run in a ThreadPoolExecutor — each is an
    independent network / IPC call (osascript, icalBuddy, sqlite, Google
    HTTP, Open-Meteo HTTP), and serial execution added ~3-5s to tasks-mode
    latency for no correctness win. Each fetcher already silent-fails; the
    wrapper captures exceptions per-future so one slow/broken service can't
    take down the others.
    """
    from concurrent.futures import ThreadPoolExecutor

    def _safe(fn, *args, **kwargs):
        try:
            return fn(*args, **kwargs)
        except Exception:
            return None

    ev: dict = {}
    # System services — fan out in parallel. Max_workers matches the fetcher
    # count so each gets a thread; overhead is negligible vs the seconds
    # saved. No shared mutable state — each worker returns a plain value.
    with ThreadPoolExecutor(max_workers=6) as ex:
        f_mail = ex.submit(_safe, _fetch_mail_unread)
        f_rem = ex.submit(
            _safe, _fetch_reminders_due, now,
            int(scope["reminders_horizon"]), 40,
        )
        f_cal = ex.submit(
            _safe, _fetch_calendar_ahead, int(scope["calendar_ahead"]),
        )
        f_wa = ex.submit(_safe, _fetch_whatsapp_unread, 24, 8)
        f_weather = ex.submit(_safe, _fetch_weather_rain)
        f_gmail = ex.submit(_safe, _fetch_gmail_evidence, now)

        mail_v = f_mail.result()
        rem_v = f_rem.result()
        cal_v = f_cal.result()
        wa_v = f_wa.result()
        weather_v = f_weather.result()
        gmail_v = f_gmail.result()

    if mail_v is not None:
        ev["mail_unread"] = mail_v
    if rem_v is not None:
        ev["reminders"] = rem_v
    if cal_v is not None:
        ev["calendar_range"] = cal_v
    if wa_v is not None:
        ev["whatsapp"] = wa_v
    if weather_v is not None:
        ev["weather"] = weather_v
    if gmail_v is not None:
        ev["gmail"] = gmail_v

    # Per-vault — loops + contradictions. Stale threshold mirrors
    # `_pendientes_collect` (14 days). Cap per vault at 8 to avoid blowing
    # the LLM context when both vaults are active.
    all_stale: list[dict] = []
    all_activo: list[dict] = []
    all_contrad: list[dict] = []
    stale_days = 14
    for vname, vpath in (vaults or []):
        with contextlib.suppress(Exception):
            loops = _pendientes_extract_loops_fast(vpath, days=14, max_items=40)
            loops.sort(key=lambda x: x.get("age_days", 0), reverse=True)
            for loop in loops:
                loop["_vault"] = vname
            stale = [x for x in loops if x.get("age_days", 0) >= stale_days][:5]
            activo = [x for x in loops if x.get("age_days", 0) < stale_days][:5]
            all_stale.extend(stale)
            all_activo.extend(activo)
        with contextlib.suppress(Exception):
            # Contradictions log is per-vault via CONTRADICTION_LOG_PATH which
            # is global — but we'll still iterate to keep the interface
            # symmetric if per-vault logs appear later.
            contrad = _pendientes_recent_contradictions(
                CONTRADICTION_LOG_PATH, now, days=14,
            )
            for c in contrad:
                c["_vault"] = vname
            all_contrad.extend(contrad)
    all_stale.sort(key=lambda x: x.get("age_days", 0), reverse=True)
    all_activo.sort(key=lambda x: x.get("age_days", 0), reverse=True)
    ev["loops_stale"] = all_stale[:8]
    ev["loops_activo"] = all_activo[:8]
    # Dedup contradictions by subject_path (global log would repeat entries)
    seen = set()
    dedup_contrad = []
    for c in all_contrad:
        key = c.get("subject_path", "")
        if key and key not in seen:
            seen.add(key)
            dedup_contrad.append(c)
    ev["contradictions"] = dedup_contrad[:5]
    return ev


def _format_scoped_tasks_context(
    ev: dict, urgent: list[str], now: datetime, scope: dict,
) -> str:
    """Markdown evidence blob for the LLM, scope label front-and-centre."""
    lines: list[str] = [
        f"# Evidencia de servicios · {now.strftime('%Y-%m-%d %H:%M')}",
        f"**Ventana temporal pedida:** {scope['label']}",
    ]
    if urgent:
        lines.append(f"\n## 🚨 Urgente / Overdue ({len(urgent)})")
        lines.extend(f"- {u}" for u in urgent)
    cal = ev.get("calendar_range") or ev.get("calendar") or []
    if cal:
        lines.append(f"\n## 📅 Calendar ({len(cal)} eventos)")
        for e in cal[:20]:
            when_bits = [b for b in (e.get("date_label"), e.get("time_range")) if b]
            if not when_bits and e.get("start"):
                when_bits = [e["start"]]
            when = " · ".join(when_bits) or "sin hora"
            lines.append(f"- {when} — {e.get('title','')}")
    rem = ev.get("reminders") or []
    if rem:
        lines.append(f"\n## 📌 Apple Reminders ({len(rem)})")
        for bucket in ("overdue", "today", "upcoming", "undated"):
            bucket_items = [x for x in rem if (x.get("bucket") or "") == bucket]
            for r in bucket_items[:10]:
                due = f" (due {r['due']})" if r.get("due") else ""
                lst = f" [{r['list']}]" if r.get("list") else ""
                lines.append(f"- **{bucket}**: {r.get('name','')}{due}{lst}")
    gm = ev.get("gmail") or {}
    awaiting = gm.get("awaiting_reply") or []
    if awaiting:
        lines.append(f"\n## 📧 Gmail awaiting reply ({len(awaiting)})")
        for m in awaiting[:8]:
            lines.append(
                f"- {m.get('days_old',0)}d · {m.get('subject','')} — {m.get('from','')}"
            )
    mail = ev.get("mail_unread") or []
    if mail:
        lines.append(f"\n## 📬 Apple Mail unread 36h ({len(mail)})")
        for m in mail[:5]:
            vip = "VIP · " if m.get("is_vip") else ""
            lines.append(f"- {vip}{m.get('subject','')} — {m.get('sender','')}")
    wa = ev.get("whatsapp") or []
    if wa:
        total = sum(int(w.get("count", 0)) for w in wa)
        lines.append(
            f"\n## 💬 WhatsApp últimas 24h ({len(wa)} chats · {total} msgs)"
        )
        for w in wa[:10]:
            snip = (w.get("last_snippet") or "").strip()[:100]
            snip_part = f' — "{snip}"' if snip else ""
            lines.append(
                f"- {w.get('name','?')} ({w.get('count',0)} msgs){snip_part}"
            )
    stale = ev.get("loops_stale") or []
    activo = ev.get("loops_activo") or []
    if stale or activo:
        vault_names = sorted({
            l.get("_vault", "") for l in (stale + activo) if l.get("_vault")
        })
        vault_tag = f" ({', '.join(vault_names)})" if vault_names else ""
        lines.append(
            f"\n## 📁 Vault loops{vault_tag} "
            f"({len(stale)} stale · {len(activo)} activo)"
        )
        for it in stale[:5]:
            src = Path(it["source_note"]).stem
            vn = it.get("_vault", "")
            vprefix = f"[{vn}] " if vn else ""
            lines.append(
                f"- {vprefix}stale {it.get('age_days',0)}d: "
                f"{it.get('loop_text','')[:100]} [[{src}]]"
            )
        for it in activo[:5]:
            src = Path(it["source_note"]).stem
            vn = it.get("_vault", "")
            vprefix = f"[{vn}] " if vn else ""
            lines.append(
                f"- {vprefix}activo {it.get('age_days',0)}d: "
                f"{it.get('loop_text','')[:100]} [[{src}]]"
            )
    return "\n".join(lines)


def _build_tasks_system_rules(scope: dict) -> str:
    """SYSTEM prompt with concrete time-window embedded."""
    return (
        "Sos un asistente personal que organiza la agenda del usuario a "
        "partir de evidencia EN VIVO de sus servicios.\n\n"
        f"VENTANA TEMPORAL SOLICITADA: {scope['label']}.\n\n"
        "REGLA DE ORO: renderizá TODAS las secciones que el CONTEXTO trae "
        "con al menos 1 item. No te quedes sólo con las primeras 2 — el "
        "usuario necesita ver todos los frentes abiertos.\n\n"
        "Qué incluir (por sección):\n"
        "• 🚨 Urgente / Overdue — SIEMPRE mostrar todos los items listados.\n"
        "• 📅 Calendar — mostrar todos los eventos del CONTEXTO (ya fueron "
        "filtrados por la ventana al obtenerlos).\n"
        "• 📌 Reminders — mostrar items `overdue` y `undated` SIEMPRE "
        "(son tareas actuales, no futuras). De `today` / `upcoming`, "
        "mostrar los que caigan dentro de la ventana.\n"
        "• 📧 Gmail awaiting reply — SIEMPRE mostrar. Son mails a los que "
        "el usuario NO respondió; son tareas pendientes del ahora, no "
        "del futuro.\n"
        "• 📬 Apple Mail unread — SIEMPRE mostrar si el CONTEXTO trae "
        "items. Son mails sin leer en las últimas 36h; el usuario quiere "
        "verlos junto al resto de la bandeja.\n"
        "• 💬 WhatsApp últimas 24h — mostrar como 'contexto de lo que se "
        "está conversando', no como tareas. Breve (3-5 chats top).\n"
        "• 📁 Vault loops — SIEMPRE mostrar activos; stale sólo si hay "
        "espacio (máx 3).\n\n"
        "Formato:\n"
        "- Español, encabezados markdown con emoji, bullets con `-`.\n"
        "- Una línea por item, sin elaborar. Calendar: 'día + hora + "
        "título'. Reminders/loops: nombre + (lista o nota).\n"
        "- Orden de secciones: 🚨 Urgente → 📅 Calendar → 📌 Reminders "
        "→ 📧 Gmail → 📬 Mail → 📁 Loops → 💬 WhatsApp (al final, "
        "como contexto).\n"
        "- Omití secciones que NO vienen en el CONTEXTO o que quedan "
        "vacías tras el filtro.\n\n"
        "No inventes tareas, plazos ni eventos que no estén literalmente "
        "en el CONTEXTO. Si el CONTEXTO no trae NADA útil, respondé "
        "exactamente: 'No tengo nada trackeado para esa ventana.' y "
        "parate ahí."
    )


def _tasks_services_consulted(ev: dict) -> list[str]:
    out: list[str] = []
    if (ev.get("gmail") or {}).get("awaiting_reply"):
        out.append("Gmail")
    if ev.get("mail_unread"):
        out.append("Apple Mail")
    if ev.get("whatsapp"):
        out.append("WhatsApp")
    if ev.get("reminders"):
        out.append("Reminders")
    if ev.get("calendar_range") or ev.get("calendar"):
        out.append("Calendar")
    if ev.get("loops_stale") or ev.get("loops_activo"):
        out.append("Vault loops")
    return out


@cli.command()
@click.option("--host", default="127.0.0.1", help="Bind address")
@click.option("--port", default=7832, type=int, help="Port number")
def serve(host: str, port: int):
    """Persistent HTTP query server — keeps models warm between requests.

    Designed for WhatsApp/bot integrations that need fast response times.
    Eliminates the ~5s cold start of subprocess-per-query by keeping the
    reranker, embedder, and BM25 corpus resident in memory.

    Endpoints:
      GET  /health  — liveness + chunk count
      POST /query   — full retrieve + generate pipeline, returns JSON
    """
    import json as _json
    from http.server import HTTPServer, BaseHTTPRequestHandler

    col = get_db()
    if col.count() == 0:
        console.print("[red]Índice vacío. Ejecuta: rag index[/red]")
        return

    # Eager warmup — block until all models are ready.
    console.print("[dim]Warming up reranker…[/dim]")
    get_reranker()
    console.print("[dim]Warming up embedder…[/dim]")
    embed(["warmup"])
    # In-process bge-m3 SentenceTransformer — launchd sets RAG_LOCAL_EMBED=1
    # on the serve plist so query embeds go through the MPS fast path. Without
    # this warmup the FIRST WhatsApp turn after a daemon restart paid ~4s of
    # cold load on the critical path (confirmed 2026-04-21 in
    # rag_queries.extra_json: embed_ms 3455/4137/4898 on the first few turns,
    # dropping to 262/402 once resident). Self-gates on _local_embed_enabled().
    if _warmup_local_embedder():
        console.print("[dim]Warming up local bge-m3 embedder…[/dim]")
    console.print("[dim]Loading BM25 corpus…[/dim]")
    _load_corpus(col)
    chat_model = resolve_chat_model()
    # Pre-cargar el chat model en VRAM con un call mínimo. Sin esto la primera
    # query real paga el cold-start del LLM (command-r ~20-30s extra).
    console.print("[dim]Warming up chat model…[/dim]")
    try:
        for _ in ollama.chat(
            model=chat_model,
            messages=[{"role": "user", "content": "hi"}],
            options={**CHAT_OPTIONS, "num_predict": 1},
            stream=True,
            keep_alive=chat_keep_alive(chat_model),
        ):
            pass
    except Exception:
        pass  # Best-effort; si falla la primera query paga el costo.
    console.print("[green]All models warm.[/green]")

    # Arrancar el memory-pressure watchdog — evita beachballs si `rag do` +
    # web server + otras apps saturan los 36 GB mientras serve está corriendo.
    # Ver comentario extenso arriba de `_system_memory_used_pct()`.
    start_memory_pressure_watchdog()

    # ── Response cache — queries repetidas instantáneas ─────────────────────
    # WA users retype consultas idénticas ("llueve hoy?", "test") con alta
    # frecuencia; cachear evita re-correr embed + retrieve + rerank + LLM
    # (~20-30s) cuando nada cambió. Key: (question, session_id). TTL 5min
    # — balance entre freshness (notas nuevas indexadas) y hit rate. Cap 64
    # entries (LRU) — budget de memoria ~200KB.
    _serve_cache: dict[str, tuple[float, dict]] = {}
    _SERVE_CACHE_MAX = 64
    _SERVE_CACHE_TTL = 300.0  # seconds

    def _cache_get(key: str) -> dict | None:
        hit = _serve_cache.get(key)
        if not hit:
            return None
        ts, payload = hit
        if time.time() - ts > _SERVE_CACHE_TTL:
            _serve_cache.pop(key, None)
            return None
        return payload

    def _cache_put(key: str, payload: dict) -> None:
        if len(_serve_cache) >= _SERVE_CACHE_MAX:
            # Drop oldest (insertion order). Dict preserves order in 3.7+.
            try:
                _serve_cache.pop(next(iter(_serve_cache)))
            except StopIteration:
                pass
        _serve_cache[key] = (time.time(), payload)

    def _handle_query(body: dict) -> dict:
        question = body.get("question", "").strip()
        if not question:
            return {"error": "empty question"}

        k = max(1, min(body.get("k", RERANK_TOP), 15))
        qfolder = body.get("folder")
        qtag = body.get("tag")
        sid = body.get("session_id")
        force = body.get("force", False)
        multi_q = body.get("multi_query", True)
        loose = body.get("loose", False)
        # num_predict override — default 256 para chat surfaces (WA/bot).
        # Respuestas median 38 chars, p95 236 tok; 256 deja buffer ajustado
        # y cap gen time a ~25s a 10 tok/s peor caso. CLI usa CHAT_OPTIONS=384.
        predict_cap = int(body.get("num_predict", 256))

        # Emit "received" event before processing — lets the dashboard surface
        # in-flight queries even when retrieval/generation hangs (the prior
        # behavior was to log only on success, so failures silently disappeared
        # from analytics).
        try:
            log_query_event({
                "cmd": "serve.received", "q": question[:200],
                "session": sid, "folder": qfolder, "tag": qtag,
            })
        except Exception:
            pass
        # Deep retrieval off-default para bot WA: el segundo pase duplica
        # retrieve + agrega 1 judge call (5-15s). El path rápido responde
        # suficientemente bien en la mayoría de queries reales.
        deep = body.get("deep", False)

        # Cache check — questiones idénticas en la misma sesión/vault sirven
        # de cache. Skip cuando `force` (usuario pidió re-run) o filtros
        # explícitos (cambian la respuesta sin cambiar la pregunta).
        cache_key = f"{sid or ''}|{qfolder or ''}|{qtag or ''}|{loose}|{question}"

        # WhatsApp cross-reference — when the query mentions a person from
        # 99-Mentions/, surface the last 3 WA messages + optional propose
        # card. Computed fresh on every call (bypasses the 5min cache)
        # because bridge messages arrive continuously; the cache holds the
        # expensive LLM answer, not the cheap SQL lookup. Failure returns
        # None silently — absent cross_ref is valid state.
        try:
            wa_cross_ref = _build_wa_cross_ref(question)
        except Exception:
            wa_cross_ref = None

        # User nickname → lets the listener personalize outgoing messages
        # ("Fer, te agendo?"). Resolved from 99-Mentions/Yo.md aliases or
        # the "nombre completo" body line. None if unknown → listener
        # falls back to name-less phrasing. Cached by mtime so edits
        # propagate without a reload.
        try:
            user_nickname = _load_user_nickname()
        except Exception:
            user_nickname = None

        if not force and not qfolder and not qtag:
            cached = _cache_get(cache_key)
            if cached is not None:
                cached = {**cached, "cached": True}
                if wa_cross_ref is not None:
                    cached["wa_cross_ref"] = wa_cross_ref
                if user_nickname is not None:
                    cached["user_nickname"] = user_nickname
                return cached

        # Session
        sess = ensure_session(sid, mode="serve") if sid else None
        history = session_history(sess) if sess else None

        # Tasks / agenda intent short-circuit — vault RAG hallucinates on
        # "what do I have this week" queries (picks up recent WhatsApp
        # markdown and answers with a chat fragment). Bypass retrieve and
        # pull from the live services layer scoped to the query's window.
        if _is_tasks_query(question):
            t_tasks0 = time.perf_counter()
            scope = _detect_time_scope(question)
            # Tasks-mode always consults ALL registered vaults — user keeps
            # loops across both `home` (personal) and `work`, and wants both
            # surfaced. System services (Reminders/Gmail/Mail/Calendar/WA)
            # are fetched once; per-vault loops are labelled with their vault.
            try:
                all_vaults = resolve_vault_paths(["all"])
            except Exception:
                all_vaults = []
            try:
                if all_vaults:
                    ev = _collect_scoped_tasks_evidence_multi(
                        all_vaults, datetime.now(), scope,
                    )
                else:
                    ev = _collect_scoped_tasks_evidence(col, datetime.now(), scope)
            except Exception as exc:
                return {"error": f"servicios fallaron: {exc}"}
            urgent = _pendientes_urgent(ev, datetime.now())
            services = _tasks_services_consulted(ev)
            context = _format_scoped_tasks_context(
                ev, urgent, datetime.now(), scope,
            )
            system_rules = _build_tasks_system_rules(scope)
            t_retrieve_tasks = time.perf_counter() - t_tasks0

            if history:
                messages = (
                    [{"role": "system",
                      "content": f"{system_rules}\nCONTEXTO:\n{context}"}]
                    + history
                    + [{"role": "user", "content": question}]
                )
            else:
                messages = [{"role": "user", "content": (
                    f"{system_rules}\nCONTEXTO:\n{context}\n\n"
                    f"PREGUNTA: {question}\n\nRESPUESTA:"
                )}]

            # Tasks mode needs more tokens than the default 256 WA cap —
            # a full agenda/pendientes layout with 5-6 sections + bullets
            # easily runs 400-600 tokens. Truncation mid-section is worse
            # than a slightly longer response.
            tasks_predict_cap = max(predict_cap, 700)
            t_gen0 = time.perf_counter()
            try:
                resp = _chat_capped_client().chat(
                    model=resolve_chat_model(),
                    messages=messages,
                    options={**CHAT_OPTIONS, "num_predict": tasks_predict_cap},
                    keep_alive=chat_keep_alive(),
                )
                answer = (resp.message.content or "").strip()
            except Exception as exc:
                return {"error": f"LLM falló: {exc}"}
            t_gen = time.perf_counter() - t_gen0

            query_turn_id = new_turn_id()
            if sess:
                append_turn(sess, {
                    "q": question, "a": answer,
                    "paths": [], "top_score": 0.0,
                    "turn_id": query_turn_id, "mode": "tasks",
                })
                save_session(sess)
            try:
                log_query_event({
                    "cmd": "serve.tasks",
                    "turn_id": query_turn_id,
                    "session": sid, "q": question[:200],
                    "scope": scope["key"], "scope_label": scope["label"],
                    "services": services,
                    "n_urgent": len(urgent),
                    "n_reminders": len(ev.get("reminders") or []),
                    "n_calendar": len(
                        ev.get("calendar_range") or ev.get("calendar") or []
                    ),
                    "n_whatsapp": len(ev.get("whatsapp") or []),
                    "t_retrieve": round(t_retrieve_tasks, 3),
                    "t_gen": round(t_gen, 3),
                    "answer_len": len(answer),
                    "timing": _round_timing_ms({
                        "total_ms": (t_retrieve_tasks + t_gen) * 1000,
                        "retrieve_ms": t_retrieve_tasks * 1000,
                        "gen_ms": t_gen * 1000,
                    }),
                })
            except Exception:
                pass

            tasks_payload = {
                "answer": answer or "(respuesta vacía)",
                "sources": [],
                "mode": "tasks",
                "scope": scope["label"],
                "services": services,
                "urgent_count": len(urgent),
                "t_retrieve": round(t_retrieve_tasks, 3),
                "t_gen": round(t_gen, 3),
                "turn_id": query_turn_id,
            }
            # Cachear igual que queries normales — respuestas idénticas en <5min
            # (ej. usuario re-pregunta "qué tengo hoy") sirven del cache.
            if not force:
                _cache_put(cache_key, tasks_payload)
            return tasks_payload

        # Reformulate + expand (merged when history available)
        effective = question
        pre_variants: list[str] | None = None
        if history and multi_q:
            try:
                s_sum = session_summary(sess) if sess else None
                effective, pre_variants = reformulate_and_expand(
                    question, history, summary=s_sum,
                )
            except Exception:
                effective = question
        elif history:
            try:
                effective = reformulate_query(question, history)
            except Exception:
                effective = question

        # turn_id stamped on every serve turn so `rag feedback` / `rag fix`
        # pueden atarlo después (CLI ya lo hacía — serve estaba roto, el
        # feedback devolvía "el último turno no tiene turn_id (sesión
        # pre-upgrade)" aunque la sesión fuera fresh).
        query_turn_id = new_turn_id()
        t0 = time.perf_counter()
        result = retrieve(
            col, effective, k, qfolder, tag=qtag, precise=False,
            multi_query=multi_q, auto_filter=True, variants=pre_variants,
        )
        if (deep and result["docs"]
                and result["confidence"] < CONFIDENCE_DEEP_THRESHOLD):
            result = deep_retrieve(
                col, effective, k, qfolder, tag=qtag, precise=False,
                multi_query=multi_q, auto_filter=True, variants=pre_variants,
            )
        t_retrieve = time.perf_counter() - t0

        sources = [
            {"note": m.get("note", ""), "path": m.get("file", ""),
             "score": round(float(s), 2)}
            for m, s in zip(result["metas"], result["scores"])
        ]

        if not result["docs"]:
            return {"answer": "", "sources": [], "t_retrieve": round(t_retrieve, 3)}

        # Confidence gate — per-source threshold (scaffolding today: all
        # sources equal the baseline until production data calibrates them).
        _top_src = (result.get("metas") or [{}])[0].get("source")
        _gate = confidence_threshold_for_source(_top_src)
        if result["confidence"] < _gate and not force:
            if sess:
                append_turn(sess, {"q": question, "a": None, "gated": True,
                                   "paths": [m.get("file", "") for m in result["metas"]],
                                   "top_score": round(float(result["confidence"]), 3),
                                   "turn_id": query_turn_id})
                save_session(sess)
            gated_payload = {
                "answer": "No tengo esa información en tus notas.",
                "gated": True, "sources": sources,
                "confidence": round(float(result["confidence"]), 2),
                "t_retrieve": round(t_retrieve, 3),
            }
            if not qfolder and not qtag:
                _cache_put(cache_key, gated_payload)
            # WA cross-ref goes on top of the gated payload too — even when
            # the vault has nothing to say about an entity, their recent
            # WhatsApp activity is often the actual answer the user wanted.
            if wa_cross_ref is not None:
                gated_payload["wa_cross_ref"] = wa_cross_ref
            if user_nickname is not None:
                gated_payload["user_nickname"] = user_nickname
            return gated_payload

        # Dynamic top-k: high-confidence hits ya traen la respuesta en los 3
        # chunks más relevantes — mandar los 5 solo infla prefill sin cambiar
        # la answer. Borderline (≤0.5) sí se beneficia del pool completo
        # porque ninguno es obviamente el "el" chunk.
        send_k = 3 if result["confidence"] > 0.5 else len(result["docs"])
        ctx_docs = result["docs"][:send_k]
        ctx_metas = result["metas"][:send_k]

        # Truncar parent chunks 1200→600 chars. El reranker ya decidió que
        # este chunk es relevante; el párrafo completo rara vez aporta sobre
        # los primeros 600 chars, y el prefill escala lineal con bytes.
        # Cortamos en boundary de oración/whitespace para no mutilar texto.
        def _truncate_chunk(text: str, cap: int = 600) -> str:
            if len(text) <= cap:
                return text
            head = text[:cap]
            for boundary in ('. ', '.\n', '!\n', '?\n', '\n\n'):
                pos = head.rfind(boundary)
                if pos > cap * 0.6:
                    return head[:pos + 1] + " […]"
            pos = head.rfind(' ')
            return (head[:pos] if pos > cap * 0.6 else head) + " […]"

        # Generate. Truncate THEN format — _format_chunk_for_llm wraps the
        # body in <<<CHUNK>>> fences + redacts OTPs/secrets for prompt-injection
        # defence. Serve truncates aggressively (600 chars) for first-token
        # latency on WhatsApp chat.
        context = "\n\n---\n\n".join(
            _format_chunk_for_llm(_truncate_chunk(d), m, role="nota")
            for d, m in zip(ctx_docs, ctx_metas)
        )
        # Chat-compact rules default para serve — WA es voice/chat, necesita
        # respuestas cortas y rápidas. `loose` conserva SYSTEM_RULES (permite
        # <<ext>> para prosa externa marcada). STRICT ya no se usa en serve.
        rules = SYSTEM_RULES if loose else SYSTEM_RULES_CHAT
        ub = user_prompt_block()
        rules_full = f"{ub}{rules}" if ub else rules
        if history:
            messages = (
                [{"role": "system", "content": f"{rules_full}\nCONTEXTO:\n{context}"}]
                + history
                + [{"role": "user", "content": question}]
            )
        else:
            messages = [{"role": "user",
                         "content": f"{rules_full}\nCONTEXTO:\n{context}\n\nPREGUNTA: {question}\n\nRESPUESTA:"}]

        t_gen0 = time.perf_counter()
        parts: list[str] = []
        for chunk in ollama.chat(
            model=resolve_chat_model(), messages=messages,
            options={**CHAT_OPTIONS, "num_predict": predict_cap},
            stream=True, keep_alive=chat_keep_alive(),
        ):
            parts.append(chunk.message.content)
        t_gen = time.perf_counter() - t_gen0
        answer = convert_obsidian_links("".join(parts))

        # Session persist
        if sess:
            append_turn(sess, {
                "q": question,
                "q_reformulated": effective if effective != question else None,
                "a": answer[:500],
                "paths": [m.get("file", "") for m in result["metas"]],
                "top_score": round(float(result["confidence"]), 3),
                "turn_id": query_turn_id,
            })
            save_session(sess)

        log_query_event({
            "cmd": "serve", "q": question,
            "filters": result.get("filters_applied"),
            "variants": result.get("query_variants"),
            "paths": [m.get("file", "") for m in result["metas"]],
            "scores": [round(float(s), 2) for s in result["scores"]],
            "top_score": round(float(result["confidence"]), 2),
            "t_retrieve": round(t_retrieve, 2), "t_gen": round(t_gen, 2),
            "timing": _round_timing_ms(result.get("timing")),
            "answered": True,
        })

        payload = {
            "answer": answer, "sources": sources,
            "confidence": round(float(result["confidence"]), 2),
            "t_retrieve": round(t_retrieve, 3), "t_gen": round(t_gen, 3),
        }
        # Cache only fresh successful answers (no force, no filters).
        # Note: cache the payload WITHOUT wa_cross_ref so the next hit
        # gets a fresh lookup — added after _cache_put below.
        if not force and not qfolder and not qtag:
            _cache_put(cache_key, payload)
        if wa_cross_ref is not None:
            payload["wa_cross_ref"] = wa_cross_ref
        if user_nickname is not None:
            payload["user_nickname"] = user_nickname
        return payload

    # ── /chat — LLM directo, sin retrieval ──────────────────────────────────
    # Para mensajes conversacionales ("hola", "cómo estás") que NO quieren
    # tocar el vault. Reusa el command-r warm del serve, sin pagar retrieve
    # ni rerank (~3-5s típico para respuestas cortas vs 15-30s del /query).
    # Mantiene continuidad por session_id. El bot WA rutea bare text acá y
    # /search|/rag al /query. System prompt en `_SERVE_CHAT_SYSTEM` (módulo)
    # — ver comentarios en la definición para el razonamiento de las reglas.

    def _handle_chat(body: dict) -> dict:
        message = body.get("message", "").strip()
        if not message:
            return {"error": "empty message"}
        sid = body.get("session_id")
        predict_cap = int(body.get("num_predict", 256))

        sess = ensure_session(sid, mode="chat") if sid else None
        history = session_history(sess) if sess else None

        messages = [{"role": "system", "content": _SERVE_CHAT_SYSTEM}]
        if history:
            messages += history
        messages.append({"role": "user", "content": message})

        t0 = time.perf_counter()
        parts: list[str] = []
        try:
            for chunk in ollama.chat(
                model=resolve_chat_model(), messages=messages,
                options={**CHAT_OPTIONS, "num_predict": predict_cap},
                stream=True, keep_alive=chat_keep_alive(),
            ):
                parts.append(chunk.message.content)
        except Exception as exc:
            return {"error": f"llm failed: {exc}"}
        t_gen = time.perf_counter() - t0
        answer = "".join(parts).strip()

        chat_turn_id = new_turn_id()
        if sess:
            append_turn(sess, {
                "q": message, "a": answer[:500], "turn_id": chat_turn_id,
            })
            save_session(sess)

        try:
            log_query_event({
                "cmd": "serve.chat", "q": message[:200],
                "session": sid, "t_gen": round(t_gen, 2),
                "answered": True,
                "timing": _round_timing_ms({"total_ms": t_gen * 1000}),
            })
        except Exception:
            pass
        return {"answer": answer, "t_gen": round(t_gen, 3)}

    class _Handler(BaseHTTPRequestHandler):
        def do_GET(self):
            if self.path == "/health":
                self._json(200, {"status": "ok", "chunks": col.count()})
            else:
                self._json(404, {"error": "not found"})

        def do_POST(self):
            if self.path not in ("/query", "/chat"):
                self._json(404, {"error": "not found"})
                return
            body: dict = {}
            try:
                length = int(self.headers.get("Content-Length", 0))
                body = _json.loads(self.rfile.read(length)) if length else {}
                handler = _handle_chat if self.path == "/chat" else _handle_query
                result = handler(body)
                self._json(200, result)
            except Exception as exc:
                # Log so the dashboard surfaces failures instead of silently
                # returning 500 — log_query_event was inside the success path
                # and never fired on errors.
                try:
                    log_query_event({
                        "cmd": "serve.error",
                        "q": str(body.get("question") or body.get("message") if isinstance(body, dict) else "")[:200],
                        "session": body.get("session_id") if isinstance(body, dict) else None,
                        "error": str(exc)[:300],
                    })
                except Exception:
                    pass
                self._json(500, {"error": str(exc)})

        def _json(self, code: int, data: dict):
            payload = _json.dumps(data, ensure_ascii=False).encode()
            self.send_response(code)
            self.send_header("Content-Type", "application/json")
            self.send_header("Content-Length", str(len(payload)))
            self.end_headers()
            self.wfile.write(payload)

        def log_message(self, format, *args):  # noqa: A002
            pass  # Silence per-request logging

    server = HTTPServer((host, port), _Handler)
    console.print(f"[bold green]rag serve[/bold green] → http://{host}:{port}")
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        console.print("\n[yellow]Stopped.[/yellow]")


def _corpus_breakdown_by_source() -> list[tuple[str, int, str]]:
    """Return `[(source_label, count, last_indexed_iso)]` sorted desc by count.

    Pulls per-source chunk counts directly from the meta table. `last_indexed`
    comes from `rag_*_state` tables when available (reminders/gmail/whatsapp
    ingesters all maintain one); falls back to the content hash mtime on disk
    for `vault`. Sources without a state table show "—".

    Used by `rag stats` for the cross-source breakdown. Silent-fails per
    source — a missing state table doesn't break the overall report.
    """
    try:
        import sqlite3 as _sqlite3
        con = _sqlite3.connect(f"file:{DB_PATH / 'ragvec.db'}?mode=ro", uri=True)
    except Exception:
        return []
    try:
        cur = con.cursor()
        # Some meta tables don't have `source` column (pre-schema). Probe first.
        meta_table = f"meta_{COLLECTION_NAME}"
        try:
            rows = cur.execute(
                f'SELECT COALESCE(source, "vault") AS src, COUNT(*) '
                f'FROM "{meta_table}" GROUP BY src ORDER BY 2 DESC'
            ).fetchall()
        except Exception:
            return []
        # Per-source last_indexed. Las state tables son specific por ingester
        # — nombre + column del timestamp vivien en scripts/ingest_*.py.
        last_ts: dict[str, str] = {}
        for src, state_tbl, ts_col in [
            ("whatsapp", "rag_whatsapp_state", "updated_at"),
            ("gmail", "rag_gmail_state", "updated_at"),
            ("reminders", "rag_reminders_state", "last_seen_ts"),
            ("calendar", "rag_calendar_state", "updated_at"),
        ]:
            try:
                r = cur.execute(
                    f'SELECT MAX({ts_col}) FROM "{state_tbl}"'
                ).fetchone()
                if r and r[0]:
                    # Normalize numeric (epoch) timestamps to ISO.
                    if isinstance(r[0], (int, float)):
                        last_ts[src] = datetime.fromtimestamp(r[0]).isoformat(timespec="minutes")
                    else:
                        last_ts[src] = str(r[0])[:16]  # truncate to `YYYY-MM-DDTHH:MM`
            except Exception:
                continue
        return [(src, cnt, last_ts.get(src, "—")) for src, cnt in rows]
    finally:
        con.close()


def rag_health_report() -> dict:
    """Resumen compacto de la salud operativa del runtime.

    Devuelve un dict con tres claves:

      ``feature_deps``:
        Lista de strings describiendo features que estan default-ON por
        env pero cuya dependencia importable NO esta disponible — es decir,
        la feature aparenta estar activa pero falla silenciosamente en
        producción.  Hoy cubre:

          - RAG_EXTRACT_ENTITIES ON + gliner ausente (28+ dropping
            `gliner_import_failed` a silent_errors.jsonl/dia cuando el
            paquete `obsidian-rag[entities]` no se instaló).

        El operador las ve en `rag stats` y puede ejecutar
        `uv pip install obsidian-rag[entities]` o `export RAG_EXTRACT_ENTITIES=0`
        para silenciar el warning.

      ``silent_errors_24h``:
        `{where: count}` agregando todas las entradas de
        `SILENT_ERRORS_LOG_PATH` con `ts` dentro de las ultimas 24h.
        Tolerancia total a corrupción: líneas no-JSON o sin `ts` se
        skipean silenciosamente.

      ``sql_state_errors_24h``:
        Mismo shape pero sobre `_SQL_STATE_ERROR_LOG`, agrupado por
        `event`. Permite detectar de un vistazo si el retry wrapper
        esta absorbiendo contención o si algún error no-transient está
        escalando (e.g. `disk I/O error`).

    Todo read-only; nunca raisea (siempre retorna un dict con las 3
    claves, aunque los valores sean vacíos).
    """
    from datetime import datetime as _dt, timedelta as _td
    report: dict = {
        "feature_deps": [],
        "silent_errors_24h": {},
        "sql_state_errors_24h": {},
        # Post 2026-04-22 audit: surfacing cache stats in rag stats so the
        # operator can spot "0 hits on 1000 queries" without raw SQL.
        "cache_stats": {
            "rows": None,
            "total_hits": None,
            "hit_rate_24h": None,
            "threshold": _SEMANTIC_CACHE_COSINE,
        },
    }

    # ── silent_errors.jsonl / sql_state_errors.jsonl rollup ──
    # (computed first so the feature_deps block below can also infer a
    # degraded feature from repeated failures even when the sticky flag
    # hasn't been set in THIS process — `rag stats` itself never calls
    # `_get_gliner_model`, but the indexer/ingesters did, and their
    # misses land in the shared log.)
    cutoff = _dt.now() - _td(hours=24)

    def _rollup(path: Path, key_field: str) -> dict[str, int]:
        counts: dict[str, int] = {}
        try:
            if not path.is_file():
                return counts
            with path.open("r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        rec = json.loads(line)
                    except Exception:
                        continue
                    ts = rec.get("ts")
                    if not ts:
                        continue
                    try:
                        # ts format: "YYYY-MM-DDTHH:MM:SS"
                        rec_dt = _dt.fromisoformat(ts.rstrip("Z"))
                    except Exception:
                        continue
                    if rec_dt < cutoff:
                        continue
                    key = rec.get(key_field) or "(unknown)"
                    counts[key] = counts.get(key, 0) + 1
        except Exception:
            pass
        return counts

    report["silent_errors_24h"] = _rollup(SILENT_ERRORS_LOG_PATH, "where")
    report["sql_state_errors_24h"] = _rollup(_SQL_STATE_ERROR_LOG, "event")

    # ── feature deps ──
    # RAG_EXTRACT_ENTITIES default ON + gliner soft-dep. Flag on EITHER
    # the sticky in-process marker (this process tried + failed) OR
    # recent 24h evidence from the shared log (other processes keep
    # failing). Ensures `rag stats` surfaces the issue even though
    # `rag stats` itself never imports gliner.
    gliner_evidence = (
        report["silent_errors_24h"].get("gliner_import_failed", 0)
        + report["silent_errors_24h"].get("gliner_load_failed", 0)
    )
    if _entity_extraction_enabled() and (_gliner_load_failed or gliner_evidence > 0):
        report["feature_deps"].append(
            "RAG_EXTRACT_ENTITIES=1 pero `gliner` no se pudo importar — "
            "entity extraction roto (corre `uv pip install obsidian-rag[entities]` "
            "o seteá `RAG_EXTRACT_ENTITIES=0` para silenciar)"
        )

    # ── cache_stats: tamaño de la tabla + hit rate 24h ──
    # Lee de `rag_response_cache` + cuenta `"cache_hit":true` en
    # `rag_queries.extra_json`. Degrada gracefully si la tabla no existe
    # o la conexión falla (DB nueva, telemetry.db missing en un host
    # recién clonado, etc.) — el panel siempre renderea, con valores
    # None cuando no hay datos.
    try:
        with _ragvec_state_conn() as _hc_conn:
            try:
                _row = _hc_conn.execute(
                    "SELECT COUNT(*), COALESCE(SUM(hit_count), 0) "
                    "FROM rag_response_cache"
                ).fetchone()
                report["cache_stats"]["rows"] = int(_row[0] or 0)
                report["cache_stats"]["total_hits"] = int(_row[1] or 0)
            except Exception:
                # Tabla no existe aún — DB fresca pre-GC#1.
                report["cache_stats"]["rows"] = 0
                report["cache_stats"]["total_hits"] = 0
            try:
                # IMPORTANTE: filtrar por `cmd IN (user query cmds)` — antes
                # del 2026-04-22 el denominador contaba también rows de
                # `cmd=followup`/`cmd=read` (611 de 1667 en 7 días) que
                # son jobs no queries. El helper `is_user_query()` expone
                # el allowlist central; aquí materializamos la cláusula
                # SQL desde el set para mantener coherencia single-source.
                _placeholders = ",".join("?" * len(_USER_QUERY_CMDS))
                _row2 = _hc_conn.execute(
                    "SELECT "
                    " SUM(CASE WHEN extra_json LIKE '%\"cache_hit\":true%' THEN 1 ELSE 0 END),"
                    " COUNT(*) "
                    "FROM rag_queries "
                    "WHERE ts > datetime('now','-1 day') "
                    "  AND q IS NOT NULL AND q != '' "
                    f"  AND cmd IN ({_placeholders})",
                    tuple(_USER_QUERY_CMDS),
                ).fetchone()
                _hits = int(_row2[0] or 0)
                _total = int(_row2[1] or 0)
                if _total > 0:
                    report["cache_stats"]["hit_rate_24h"] = _hits / _total
            except Exception:
                pass
    except Exception:
        # _ragvec_state_conn failed to open (missing DB, locked beyond
        # retry, etc.). Leave the None defaults — `rag stats` renders
        # "cache: (unavailable)" in that branch.
        pass

    return report


@cli.command()
def stats():
    """Estado del índice."""
    col = get_db()
    count = col.count()
    try:
        urls_count = get_urls_db().count()
    except Exception:
        urls_count = 0
    console.print(f"[cyan]Chunks indexados:[/cyan] {count}")

    # Cross-source breakdown. Solo renderea si hay ≥2 sources en el corpus —
    # en un deploy vault-only no aporta nada.
    breakdown = _corpus_breakdown_by_source()
    distinct_sources = {src for src, _, _ in breakdown}
    if len(distinct_sources) >= 2:
        tbl = Table(
            show_header=True, box=None, pad_edge=False, padding=(0, 1),
            title_style="cyan", title="Por source",
        )
        tbl.add_column("source", style="bold")
        tbl.add_column("chunks", justify="right")
        tbl.add_column("%", justify="right", style="dim")
        tbl.add_column("last indexed", style="dim")
        total = sum(cnt for _, cnt, _ in breakdown)
        for src, cnt, last_ts in breakdown:
            pct = f"{100 * cnt / total:.1f}%" if total else "—"
            tbl.add_row(src or "(null)", f"{cnt:,}", pct, last_ts)
        console.print(tbl)

    console.print(f"[cyan]URLs indexadas:[/cyan] {urls_count}  [dim]({URLS_COLLECTION_NAME})[/dim]")
    # Identificar la fuente del vault (env / registry / default) ayuda al
    # debug en setups multi-vault.
    vault_src = "default"
    if os.environ.get("OBSIDIAN_RAG_VAULT"):
        vault_src = "env"
    else:
        _vcfg = _load_vaults_config()
        if _vcfg["current"] and _vcfg["current"] in _vcfg["vaults"]:
            vault_src = f"registry · {_vcfg['current']}"
    console.print(f"[cyan]Vault:[/cyan] {VAULT_PATH}  [dim]({vault_src})[/dim]")
    console.print(f"[cyan]DB dir:[/cyan] {DB_PATH}")

    def _fmt_db_size(p: Path) -> str:
        try:
            b = p.stat().st_size
            wal = p.with_suffix(p.suffix + "-wal")
            wal_b = wal.stat().st_size if wal.is_file() else 0
            total_mb = (b + wal_b) / (1024 * 1024)
            wal_note = f" + WAL {wal_b / (1024*1024):.1f}MB" if wal_b else ""
            return f"{total_mb:.1f}MB{wal_note}"
        except OSError:
            return "[dim](missing)[/dim]"

    ragvec_db = DB_PATH / "ragvec.db"
    telemetry_db = DB_PATH / _TELEMETRY_DB_FILENAME
    console.print(f"[cyan]  ragvec.db:[/cyan]    {_fmt_db_size(ragvec_db)}  [dim](vec + meta + ingester cursors)[/dim]")
    console.print(f"[cyan]  telemetry.db:[/cyan] {_fmt_db_size(telemetry_db)}  [dim](rag_* telemetry + entity graph + OCR cache)[/dim]")
    console.print(f"[cyan]Colección:[/cyan] {COLLECTION_NAME}")
    console.print(f"[cyan]Embed model:[/cyan] {EMBED_MODEL}")
    try:
        resolved = resolve_chat_model()
    except Exception as e:
        resolved = f"[red]{e}[/red]"
    console.print(f"[cyan]Chat model:[/cyan] {resolved}  [dim](preference: {', '.join(CHAT_MODEL_PREFERENCE)})[/dim]")
    console.print(f"[cyan]Helper model:[/cyan] {HELPER_MODEL}")
    console.print(f"[cyan]Reranker:[/cyan] {RERANKER_MODEL}")
    console.print("[cyan]Pipeline:[/cyan] HyDE + BM25 + RRF + cross-encoder rerank")
    pos, neg = feedback_counts()
    if pos or neg:
        console.print(f"[cyan]Feedback:[/cyan] 👍 {pos} · 👎 {neg}  [dim]({FEEDBACK_PATH})[/dim]")

    # ── Health ─────────────────────────────────────────────────────────────
    # Features ON por default con deps faltantes + rollup de últimas 24h
    # de silent_errors.jsonl y sql_state_errors.jsonl. Antes de este panel
    # el operador no tenía forma de saber que RAG_EXTRACT_ENTITIES=1 estaba
    # roto sin hacer `cat ~/.local/share/obsidian-rag/silent_errors.jsonl`.
    try:
        hr = rag_health_report()
    except Exception:
        hr = {"feature_deps": [], "silent_errors_24h": {}, "sql_state_errors_24h": {}}

    deps = hr.get("feature_deps") or []
    se24 = hr.get("silent_errors_24h") or {}
    sse24 = hr.get("sql_state_errors_24h") or {}
    cs = hr.get("cache_stats") or {}

    # Cache panel siempre se renderiza si la tabla existe (rows is not None),
    # aunque hit_rate sea 0 — el operador quiere ver "0 hits" para diagnosticar.
    _has_cache_info = cs.get("rows") is not None

    if deps or se24 or sse24 or _has_cache_info:
        console.print()
        console.print("[bold cyan]Health (últimas 24h):[/bold cyan]")
        for msg in deps:
            # `markup=False`: the message may contain `[entities]`, `[nli]`
            # literals that rich would otherwise interpret as style tags
            # and silently drop.
            console.print(f"  ⚠ {msg}", style="yellow", markup=False, highlight=False)
        if _has_cache_info:
            _rows = cs.get("rows", 0) or 0
            _hit_rate = cs.get("hit_rate_24h")
            _thr = cs.get("threshold")
            _hit_rate_str = (
                f"{_hit_rate:.1%}" if isinstance(_hit_rate, (int, float)) else "—"
            )
            _thr_str = f"{_thr:.2f}" if isinstance(_thr, (int, float)) else "—"
            _line = (
                f"  semantic cache: rows={_rows}, hit_rate(24h)={_hit_rate_str}, "
                f"cosine_threshold={_thr_str}"
            )
            # Si hit rate es 0% sobre >50 queries, marcar en amarillo — señal
            # de que el cache no está absorbiendo queries repetidas.
            if (isinstance(_hit_rate, (int, float)) and _hit_rate < 0.01
                    and _rows < 50):
                console.print(
                    _line + "  ⚠ tabla casi vacía (revisar sql_state_errors)",
                    style="yellow", markup=False,
                )
            else:
                console.print(_line, style="dim", markup=False)
        if se24:
            # Ordenado por count desc — el operador quiere ver el más ruidoso primero.
            top = sorted(se24.items(), key=lambda kv: kv[1], reverse=True)[:6]
            console.print(
                "  silent_errors: "
                + ", ".join(f"{k}={v}" for k, v in top),
                style="dim", markup=False,
            )
        if sse24:
            top = sorted(sse24.items(), key=lambda kv: kv[1], reverse=True)[:6]
            console.print(
                "  sql_state_errors: "
                + ", ".join(f"{k}={v}" for k, v in top),
                style="dim", markup=False,
            )


@cli.command("open")
@click.argument("path")
@click.option("--query", default=None, help="Triggering query, forwarded to behavior log")
@click.option("--rank", default=None, type=int, help="1-indexed rank among results when opened")
@click.option("--source", default="cli", help="Event source: cli | whatsapp | web | brief")
@click.option("--session", default=None, help="Session id, forwarded to behavior log")
def open_cmd(path: str, query: str | None, rank: int | None, source: str, session: str | None):
    """Open a vault note and record an open event in behavior.jsonl.

    PATH may be vault-relative (e.g. 01-Projects/foo.md) or absolute.
    The file is opened via macOS `open` (hands off to the default .md handler).
    An open event is appended to ~/.local/share/obsidian-rag/behavior.jsonl
    for use by the ranker-vivo pipeline.

    When RAG_TRACK_OPENS=1 terminals emit x-rag-open:// URIs instead of
    file:// — registering `rag open` as the x-rag-open handler routes clicks
    through this command so every note-open from query results is logged.
    """
    import subprocess

    p = Path(path)
    if not p.is_absolute():
        resolved = VAULT_PATH / p
    else:
        resolved = p

    if not resolved.exists():
        click.echo(f"error: path not found: {resolved}", err=True)
        raise SystemExit(1)

    try:
        inside_vault = resolved.resolve().is_relative_to(VAULT_PATH.resolve())
    except Exception:
        inside_vault = False

    if inside_vault:
        rel_path = str(resolved.resolve().relative_to(VAULT_PATH.resolve()))
        ev: dict = {"source": source, "event": "open", "path": rel_path}
        if query is not None:
            ev["query"] = query
        if rank is not None:
            ev["rank"] = rank
        if session is not None:
            ev["session"] = session
        log_behavior_event(ev)
    else:
        ev_ext: dict = {"source": source, "event": "open_external"}
        if query is not None:
            ev_ext["query"] = query
        if session is not None:
            ev_ext["session"] = session
        log_behavior_event(ev_ext)

    subprocess.run(["open", str(resolved)])


@cli.group()
def vault():
    """Multi-vault: registrar / cambiar / listar vaults de Obsidian.

    El registry vive en ~/.config/obsidian-rag/vaults.json. Cada vault
    obtiene su propia colección de sqlite-vec automáticamente (namespacing
    por hash del path) — switchear no contamina ni cruza datos.

    Precedencia para resolver el vault activo:
      1. OBSIDIAN_RAG_VAULT env var (override per-invocación, gana siempre).
      2. `vault use <name>` (el "current" del registry, persistente).
      3. Default iCloud Notes (legacy, para usuarios single-vault).
    """


@vault.command("add")
@click.argument("name")
@click.argument("path", type=click.Path(
    exists=True, file_okay=False, dir_okay=True, resolve_path=True,
))
def vault_add(name: str, path: str):
    """Registrar un vault con un nombre. Si es el primero, queda activo."""
    cfg = _load_vaults_config()
    if name in cfg["vaults"] and cfg["vaults"][name] != path:
        console.print(
            f"[yellow]Sobreescribiendo[/yellow] '{name}': "
            f"{cfg['vaults'][name]} → {path}"
        )
    cfg["vaults"][name] = path
    if not cfg["current"]:
        cfg["current"] = name
        marker = " (activo)"
    else:
        marker = ""
    _save_vaults_config(cfg)
    console.print(f"[green]✓[/green] vault [bold]{name}[/bold] → {path}{marker}")


@vault.command("list")
def vault_list():
    """Listar vaults registrados, marcando el activo."""
    cfg = _load_vaults_config()
    if not cfg["vaults"]:
        console.print(
            "[dim]Sin vaults registrados.[/dim] "
            "Usá [bold]rag vault add <name> <path>[/bold] para empezar."
        )
        console.print(f"[dim]Default actual: {_DEFAULT_VAULT}[/dim]")
        return
    cur = cfg["current"]
    env = os.environ.get("OBSIDIAN_RAG_VAULT")
    for name, path in cfg["vaults"].items():
        marker = "[green]→[/green]" if name == cur else "  "
        console.print(f"  {marker} [bold]{name}[/bold]  [dim]{path}[/dim]")
    if env:
        console.print(
            f"\n[yellow]⚠ OBSIDIAN_RAG_VAULT está seteado[/yellow] "
            f"[dim]({env})[/dim] — overridea el registry."
        )


@vault.command("use")
@click.argument("name")
def vault_use(name: str):
    """Cambiar al vault NAME (persistente). Afecta a futuras invocaciones."""
    cfg = _load_vaults_config()
    if name not in cfg["vaults"]:
        registered = ", ".join(cfg["vaults"]) or "(ninguno)"
        console.print(
            f"[red]vault '{name}' no registrado.[/red] "
            f"Registrados: {registered}"
        )
        return
    cfg["current"] = name
    _save_vaults_config(cfg)
    path = cfg["vaults"][name]
    console.print(f"[green]✓[/green] vault activo: [bold]{name}[/bold]  [dim]({path})[/dim]")
    if os.environ.get("OBSIDIAN_RAG_VAULT"):
        console.print(
            "[yellow]⚠[/yellow] OBSIDIAN_RAG_VAULT está seteado — "
            "lo seguirá overrideando hasta que lo desetees."
        )


@vault.command("current")
def vault_current():
    """Mostrar el vault que se va a usar y por qué."""
    env = os.environ.get("OBSIDIAN_RAG_VAULT")
    if env:
        console.print(f"[bold]env[/bold] OBSIDIAN_RAG_VAULT → [cyan]{env}[/cyan]")
        return
    cfg = _load_vaults_config()
    cur = cfg["current"]
    if cur and cur in cfg["vaults"]:
        console.print(
            f"[bold]registry[/bold] [bold]{cur}[/bold] → "
            f"[cyan]{cfg['vaults'][cur]}[/cyan]"
        )
        return
    console.print(f"[bold]default[/bold] → [cyan]{_DEFAULT_VAULT}[/cyan]")


@vault.command("remove")
@click.argument("name")
def vault_remove(name: str):
    """Quitar un vault del registry. NO borra archivos del disco."""
    cfg = _load_vaults_config()
    if name not in cfg["vaults"]:
        console.print(f"[red]vault '{name}' no registrado.[/red]")
        return
    del cfg["vaults"][name]
    if cfg["current"] == name:
        cfg["current"] = next(iter(cfg["vaults"]), None)
    _save_vaults_config(cfg)
    if cfg["current"]:
        console.print(
            f"[green]✓[/green] '{name}' removido. "
            f"Activo ahora: [bold]{cfg['current']}[/bold]"
        )
    else:
        console.print(
            f"[green]✓[/green] '{name}' removido. "
            f"Sin current — caerá al default."
        )


@cli.group()
def session():
    """Administrar sesiones conversacionales (list / show / clear / cleanup)."""


@session.command("list")
@click.option("-n", "limit", default=20, help="Máximo de sesiones a listar (default: 20)")
def session_list(limit: int):
    """Lista las sesiones recientes."""
    rows = list_sessions(limit=limit)
    if not rows:
        console.print("[dim]No hay sesiones.[/dim]")
        return
    t = Table(title=f"Sesiones ({len(rows)})", show_header=True, header_style="bold")
    t.add_column("id", style="cyan")
    t.add_column("turns", justify="right")
    t.add_column("modo", style="dim")
    t.add_column("actualizada", style="dim")
    t.add_column("primer turno")
    for r in rows:
        t.add_row(
            r["id"], str(r["turns"]), r.get("mode", ""),
            r.get("updated_at", ""), r.get("first_q", ""),
        )
    console.print(t)


@session.command("show")
@click.argument("sid")
def session_show(sid: str):
    """Muestra los turnos de una sesión."""
    s = load_session(sid)
    if not s:
        console.print(f"[red]Sesión no encontrada: {sid}[/red]")
        return
    console.print(Panel(
        f"[bold cyan]{s['id']}[/bold cyan]  [dim]· {len(s.get('turns', []))} turnos · "
        f"{s.get('mode', '')}  · creada {s.get('created_at', '')}[/dim]",
        border_style="cyan",
    ))
    for i, turn in enumerate(s.get("turns", []), 1):
        console.print()
        console.print(f"[bold]{i}. ❯[/bold] {turn.get('q', '')}")
        if turn.get("q_reformulated"):
            console.print(f"   [dim italic]reformulada: {turn['q_reformulated']}[/dim italic]")
        if turn.get("a"):
            console.print(render_response(turn["a"]))
        paths = turn.get("paths") or []
        if paths:
            console.print(f"   [dim]sources: {', '.join(paths[:3])}{'…' if len(paths) > 3 else ''}[/dim]")


@session.command("clear")
@click.argument("sid")
@click.option("--yes", is_flag=True, help="No pedir confirmación")
def session_clear(sid: str, yes: bool):
    """Borra una sesión por id."""
    try:
        p = session_path(sid)
    except ValueError as e:
        console.print(f"[red]{e}[/red]")
        return
    if not p.exists():
        console.print(f"[yellow]No existe:[/yellow] {sid}")
        return
    if not yes:
        try:
            confirm = console.input(f"Borrar sesión [cyan]{sid}[/cyan]? [y/N] ").strip().lower()
        except (KeyboardInterrupt, EOFError):
            console.print("[dim]cancelado[/dim]")
            return
        if confirm != "y":
            console.print("[dim]cancelado[/dim]")
            return
    p.unlink()
    console.print(f"[green]✓ borrada:[/green] {sid}")


@session.command("cleanup")
@click.option("--days", default=SESSION_TTL_DAYS, show_default=True,
              help="Borrar sesiones más viejas que N días (mtime)")
def session_cleanup(days: int):
    """Purga sesiones viejas."""
    removed = cleanup_sessions(ttl_days=days)
    console.print(f"[cyan]{removed}[/cyan] sesión(es) borrada(s) (TTL {days}d)")


# ── DASHBOARD ─────────────────────────────────────────────────────────────────
# Terminal-based analytics over queries.jsonl. Shows query patterns, retrieval
# quality distribution, latency breakdown, and feedback ratio.


def _dashboard_data(days: int = 30) -> dict:
    """Parse queries.jsonl into dashboard metrics."""
    entries = _scan_queries_log(days=days)
    if not entries:
        return {"n": 0}

    scores: list[float] = []
    t_retrieves: list[float] = []
    t_gens: list[float] = []
    gated = 0
    answered = 0
    topics: dict[str, int] = {}
    hours: dict[int, int] = {}
    cmds: dict[str, int] = {}

    for e in entries:
        ts_raw = e.get("ts") or e.get("timestamp")
        if ts_raw:
            try:
                hour = datetime.fromisoformat(ts_raw).hour
                hours[hour] = hours.get(hour, 0) + 1
            except Exception:
                pass

        cmd = e.get("cmd", "?")
        cmds[cmd] = cmds.get(cmd, 0) + 1

        top = e.get("top_score")
        if isinstance(top, (int, float)):
            scores.append(float(top))

        tr = e.get("t_retrieve")
        if isinstance(tr, (int, float)):
            t_retrieves.append(float(tr))

        tg = e.get("t_gen")
        if isinstance(tg, (int, float)) and tg > 0:
            t_gens.append(float(tg))

        if e.get("gated_low_confidence"):
            gated += 1
        if e.get("answered"):
            answered += 1

        # Topic extraction: first 3 words of query
        q = e.get("q", "")
        if q:
            words = q.lower().split()[:3]
            topic = " ".join(words)
            topics[topic] = topics.get(topic, 0) + 1

    # Percentiles helper
    def pct(values: list[float], p: float) -> float:
        if not values:
            return 0.0
        s = sorted(values)
        idx = int(len(s) * p / 100)
        return s[min(idx, len(s) - 1)]

    return {
        "n": len(entries),
        "days": days,
        "scores": scores,
        "t_retrieves": t_retrieves,
        "t_gens": t_gens,
        "gated": gated,
        "answered": answered,
        "topics": topics,
        "hours": hours,
        "cmds": cmds,
        "pct": pct,
    }


@cli.command()
@click.option("--days", default=30, show_default=True, help="Ventana temporal en días")
def dashboard(days: int):
    """Analytics dashboard — métricas del pipeline sobre queries.jsonl."""
    data = _dashboard_data(days)
    if data["n"] == 0:
        console.print("[yellow]Sin queries en el período.[/yellow]")
        return

    console.print()
    console.print(Rule(title="[bold cyan]Dashboard[/bold cyan]", style="cyan"))
    console.print(f"  [dim]{data['n']} queries · últimos {data['days']} días[/dim]")
    console.print()

    # ── Commands breakdown ──
    t = Table(title="Comandos", show_header=True, header_style="bold", box=None, padding=(0, 2))
    t.add_column("Comando", style="cyan")
    t.add_column("Count", justify="right")
    for cmd, count in sorted(data["cmds"].items(), key=lambda x: -x[1])[:8]:
        t.add_row(cmd, str(count))
    console.print(t)
    console.print()

    # ── Retrieval quality ──
    scores = data["scores"]
    pct = data["pct"]
    if scores:
        console.print(Rule(title="[dim]Retrieval Quality[/dim]", style="dim", characters="╌"))
        gate_rate = data["gated"] / data["n"] * 100 if data["n"] else 0
        answer_rate = data["answered"] / data["n"] * 100 if data["n"] else 0
        console.print(f"  Score p50: [bold]{pct(scores, 50):.3f}[/bold] · "
                      f"p95: [bold]{pct(scores, 95):.3f}[/bold] · "
                      f"min: {min(scores):.3f} · max: {max(scores):.3f}")
        console.print(f"  Gate rate: [{'red' if gate_rate > 30 else 'green'}]"
                      f"{gate_rate:.1f}%[/] · Answer rate: [green]{answer_rate:.1f}%[/]")
        # Score distribution histogram (inline)
        buckets = [0] * 10  # 0.0-0.1, 0.1-0.2, ..., 0.9-1.0
        for s in scores:
            clamped = max(0.0, min(s, 1.0))
            idx = min(int(clamped * 10), 9)
            buckets[idx] += 1
        max_b = max(buckets) or 1
        console.print("  Score distribution:")
        for i, b in enumerate(buckets):
            bar = "█" * int(b / max_b * 20) if b else ""
            label = f"  {i/10:.1f}-{(i+1)/10:.1f}"
            console.print(f"  {label} [{('green' if i >= 5 else 'yellow' if i >= 2 else 'red')}]{bar}[/] {b}")
        console.print()

    # ── Latency breakdown ──
    t_r = data["t_retrieves"]
    t_g = data["t_gens"]
    if t_r:
        console.print(Rule(title="[dim]Latency[/dim]", style="dim", characters="╌"))
        console.print(f"  Retrieve: p50 [bold]{pct(t_r, 50):.2f}s[/bold] · "
                      f"p95 [bold]{pct(t_r, 95):.2f}s[/bold]")
        if t_g:
            console.print(f"  Generate: p50 [bold]{pct(t_g, 50):.2f}s[/bold] · "
                          f"p95 [bold]{pct(t_g, 95):.2f}s[/bold]")
            total = [r + g for r, g in zip(t_r[:len(t_g)], t_g)]
            if total:
                console.print(f"  Total:    p50 [bold]{pct(total, 50):.2f}s[/bold] · "
                              f"p95 [bold]{pct(total, 95):.2f}s[/bold]")
        console.print()

    # ── Activity heatmap (by hour) ──
    hours = data["hours"]
    if hours:
        console.print(Rule(title="[dim]Activity by Hour[/dim]", style="dim", characters="╌"))
        max_h = max(hours.values()) or 1
        for h in range(24):
            count = hours.get(h, 0)
            bar = "█" * int(count / max_h * 30) if count else ""
            console.print(f"  {h:02d}:00 [cyan]{bar}[/] {count if count else ''}")
        console.print()

    # ── Hot topics (top queries by prefix) ──
    topics = data["topics"]
    if topics:
        console.print(Rule(title="[dim]Hot Topics[/dim]", style="dim", characters="╌"))
        for topic, count in sorted(topics.items(), key=lambda x: -x[1])[:10]:
            if count >= 2:
                console.print(f"  [bold]{count}×[/bold] {topic}")
        console.print()

    # ── Feedback stats ──
    try:
        if FEEDBACK_PATH.is_file():
            fb_lines = FEEDBACK_PATH.read_text(encoding="utf-8").splitlines()
            pos = sum(1 for l in fb_lines if '"rating": 1' in l or '"rating":1' in l)
            neg = sum(1 for l in fb_lines if '"rating": -1' in l or '"rating":-1' in l)
            corrective = sum(1 for l in fb_lines if '"corrective_path"' in l)
            console.print(Rule(title="[dim]Feedback[/dim]", style="dim", characters="╌"))
            total_fb = pos + neg
            ratio = pos / total_fb * 100 if total_fb else 0
            console.print(f"  👍 {pos} · 👎 {neg} · ratio: [{'green' if ratio > 70 else 'yellow'}]{ratio:.0f}%[/]")
            if corrective:
                console.print(f"  🎯 {corrective} corrective paths")
            console.print()
    except Exception:
        pass

    # ── Index stats (quick) ──
    try:
        col = get_db()
        n_chunks = col.count()
        console.print(Rule(title="[dim]Index[/dim]", style="dim", characters="╌"))
        console.print(f"  {n_chunks} chunks indexed")
        corpus = _load_corpus(col)
        console.print(f"  {len(corpus['tags'])} tags · "
                      f"{len(corpus['folders'])} folders · "
                      f"{len(corpus['title_to_paths'])} notes")
        pr = get_pagerank(col)
        if pr:
            top_pr = sorted(pr.items(), key=lambda x: -x[1])[:5]
            console.print("  Top PageRank:")
            for path, score in top_pr:
                console.print(f"    {score:.4f} {path}")
    except Exception:
        pass
    console.print()


# ── MAINTENANCE ──────────────────────────────────────────────────────────────
# Unified housekeeping: reindex, prune orphans, rotate logs, clean caches,
# rebuild derived state, report dead notes. Safe to run unattended (cron/launchd).

_JSONL_ROTATE_BYTES = 10 * 1024 * 1024  # 10 MB threshold for log rotation

_JSONL_LOG_PATHS: list[tuple[str, Path]] = [
    ("queries.jsonl", LOG_PATH),
    ("behavior.jsonl", BEHAVIOR_LOG_PATH),
    ("contradictions.jsonl", CONTRADICTION_LOG_PATH),
    ("ambient.jsonl", AMBIENT_LOG_PATH),
    ("ambient_state.jsonl", AMBIENT_STATE_PATH),
    ("tune.jsonl", TUNE_LOG_PATH),
    ("behavior.jsonl", BEHAVIOR_LOG_PATH),
    ("brief_written.jsonl", BRIEF_WRITTEN_PATH),
    ("brief_state.jsonl", BRIEF_STATE_PATH),
]


def _rotate_jsonl(path: Path, max_bytes: int = _JSONL_ROTATE_BYTES) -> str | None:
    """Rotate a JSONL file if it exceeds max_bytes. Keeps the most recent half
    of the lines and moves the rest to path.1. Returns description or None."""
    if not path.is_file():
        return None
    try:
        size = path.stat().st_size
    except OSError:
        return None
    if size < max_bytes:
        return None
    lines = path.read_text(encoding="utf-8").splitlines()
    if len(lines) < 2:
        return None
    keep = len(lines) // 2
    old = path.with_suffix(path.suffix + ".1")
    old.write_text("\n".join(lines[:len(lines) - keep]) + "\n", encoding="utf-8")
    path.write_text("\n".join(lines[len(lines) - keep:]) + "\n", encoding="utf-8")
    return f"{len(lines) - keep} lines kept, {len(lines) - keep} archived → {old.name} ({size / 1024:.0f} KB → {path.stat().st_size / 1024:.0f} KB)"


def _prune_context_cache(col: "SqliteVecCollection") -> int:
    """Remove context_summaries entries whose file hash is no longer in the index."""
    cache = _load_context_cache()
    if not cache:
        return 0
    existing = col.get(include=["metadatas"])
    live_hashes: set[str] = set()
    for m in existing["metadatas"]:
        h = m.get("hash", "")
        if h:
            live_hashes.add(h)
    with _context_cache_lock:
        stale = [k for k in cache if k not in live_hashes]
        for k in stale:
            del cache[k]
        if stale:
            global _context_cache_dirty
            _context_cache_dirty = True
    if stale:
        _save_context_cache()
    return len(stale)


def _prune_synthetic_q_cache(col: "SqliteVecCollection") -> int:
    """Remove synthetic_questions entries whose file hash is no longer in the index."""
    cache = _load_synthetic_q_cache()
    if not cache:
        return 0
    existing = col.get(include=["metadatas"])
    live_hashes: set[str] = set()
    for m in existing["metadatas"]:
        h = m.get("hash", "")
        if h:
            live_hashes.add(h)
    with _synthetic_q_cache_lock:
        stale = [k for k in cache if k not in live_hashes]
        for k in stale:
            del cache[k]
        if stale:
            global _synthetic_q_cache_dirty
            _synthetic_q_cache_dirty = True
    if stale:
        _save_synthetic_q_cache()
    return len(stale)


def _prune_ignored_notes(vault: Path) -> int:
    """Remove entries from ignored_notes.json whose files no longer exist."""
    paths = load_ignored_paths()
    if not paths:
        return 0
    stale = {p for p in paths if not (vault / p).exists()}
    if stale:
        save_ignored_paths(paths - stale)
    return len(stale)


def _prune_auto_index_state() -> int:
    """Remove auto_index_state entries for vaults not in the registry or default."""
    state = _auto_index_state_load()
    if not state:
        return 0
    valid_keys = {_vault_state_key(VAULT_PATH)}
    try:
        vcfg = _load_vaults_config()
        for vpath in vcfg["vaults"].values():
            valid_keys.add(_vault_state_key(Path(vpath)))
    except Exception:
        pass
    stale = [k for k in state if k not in valid_keys]
    if stale:
        for k in stale:
            del state[k]
        _auto_index_state_save(state)
    return len(stale)


_FILING_BATCH_TTL_DAYS = 90


def _prune_filing_batches(ttl_days: int = _FILING_BATCH_TTL_DAYS) -> int:
    """Delete filing batch files older than ttl_days."""
    if not FILING_BATCHES_DIR.is_dir():
        return 0
    cutoff = time.time() - ttl_days * 86400
    removed = 0
    for f in FILING_BATCHES_DIR.glob("*.jsonl"):
        try:
            if f.stat().st_mtime < cutoff:
                f.unlink()
                removed += 1
        except OSError:
            continue
    return removed


def _cleanup_tmp_files() -> int:
    """Remove orphan .tmp files from state directories (crashed writes)."""
    state_dir = Path.home() / ".local/share/obsidian-rag"
    removed = 0
    if not state_dir.is_dir():
        return 0
    for tmp in state_dir.glob("*.tmp"):
        try:
            # Only remove if older than 1 hour (avoid racing with live writes)
            if time.time() - tmp.stat().st_mtime > 3600:
                tmp.unlink()
                removed += 1
        except OSError:
            continue
    # Also check sessions dir
    if SESSIONS_DIR.is_dir():
        for tmp in SESSIONS_DIR.glob("*.tmp"):
            try:
                if time.time() - tmp.stat().st_mtime > 3600:
                    tmp.unlink()
                    removed += 1
            except OSError:
                continue
    return removed


def _check_ollama_health() -> dict:
    """Verify required Ollama models are available. Returns {model: ok/missing}."""
    required = [EMBED_MODEL, HELPER_MODEL] + list(CHAT_MODEL_PREFERENCE)
    status: dict[str, str] = {}
    try:
        available = {m.model for m in ollama.list().models}
    except Exception as e:
        return {"error": str(e)}
    for model in required:
        # ollama.list() returns full names; match with and without :latest
        found = model in available or f"{model}:latest" in available
        if not found:
            # Try prefix match (e.g. "command-r" matches "command-r:latest")
            found = any(a.startswith(model.split(":")[0] + ":") for a in available)
        status[model] = "ok" if found else "missing"
    return status


def _prune_url_orphans(vault: Path) -> int:
    """Remove URL collection entries for files no longer on disk."""
    try:
        col_urls = get_urls_db()
        all_urls = col_urls.get(include=["metadatas"])
    except Exception:
        return 0
    if not all_urls["ids"]:
        return 0
    on_disk = {
        str(p.relative_to(vault))
        for p in vault.rglob("*.md")
        if not is_excluded(str(p.relative_to(vault)))
    }
    orphan_ids = [
        id_ for id_, meta in zip(all_urls["ids"], all_urls["metadatas"])
        if meta.get("file", "") not in on_disk
    ]
    if orphan_ids:
        # Chunk deletes for predictable memory usage.
        for i in range(0, len(orphan_ids), 5000):
            col_urls.delete(ids=orphan_ids[i:i + 5000])
    return len(orphan_ids)


def _prune_feedback_orphans(vault: Path) -> int:
    """Remove feedback.jsonl entries whose paths all point to deleted notes.
    Rewrites the file in place, preserving entries that have at least one live path."""
    if not FEEDBACK_PATH.is_file():
        return 0
    on_disk = {
        str(p.relative_to(vault))
        for p in vault.rglob("*.md")
        if not is_excluded(str(p.relative_to(vault)))
    }
    lines = FEEDBACK_PATH.read_text(encoding="utf-8").splitlines()
    kept: list[str] = []
    removed = 0
    for line in lines:
        line = line.strip()
        if not line:
            continue
        try:
            ev = json.loads(line)
        except Exception:
            kept.append(line)
            continue
        paths = ev.get("paths") or []
        # Keep if any path still exists, or if it's a session-scope rating (no paths)
        if not paths or any(p in on_disk for p in paths):
            kept.append(line)
        else:
            removed += 1
    if removed:
        FEEDBACK_PATH.write_text("\n".join(kept) + "\n" if kept else "", encoding="utf-8")
    return removed


def _find_orphan_collections() -> list[str]:
    """Detect sqlite-vec collections from old schema versions or removed vaults.

    Safety invariants
    -----------------
    1. Base names are never orphaned: _COLLECTION_BASE ("obsidian_notes_v9")
       and _URLS_COLLECTION_BASE ("obsidian_urls_v1") are unconditionally added
       to `known` so that if this process was launched with OBSIDIAN_RAG_VAULT
       pointing at a non-default vault, the default vault's unsuffixed collection
       is still protected and not classified as an orphan.

    2. No recency guard is implemented — sqlite-vec has no creation timestamp in
       schema.

    3. Audit: every candidate orphan is logged via _log_collection_op before
       being returned to the caller (which may delete it).
    """
    try:
        client = SqliteVecClient(path=str(DB_PATH))
        all_cols = [c.name for c in client.list_collections()]
    except Exception:
        return []
    known = {COLLECTION_NAME, URLS_COLLECTION_NAME}
    # Unconditionally protect the base names for the default vault.
    # If this process was started with OBSIDIAN_RAG_VAULT set to a work vault,
    # COLLECTION_NAME / URLS_COLLECTION_NAME resolve to the work-vault suffixed
    # names.  The unsuffixed default-vault collections would then fall through
    # as unknown and get wrongly classified as orphans without this guard.
    known.add(_COLLECTION_BASE)
    known.add(_URLS_COLLECTION_BASE)
    # Also include collections for registered vaults
    try:
        vcfg = _load_vaults_config()
        for vpath in vcfg["vaults"].values():
            vp = Path(vpath)
            known.add(_collection_name_for_vault(vp))
            known.add(_urls_collection_name_for_vault(vp))
    except Exception:
        pass
    orphans = [c for c in all_cols if c not in known]
    # Audit every candidate before returning to caller — caller may delete them.
    for cname in orphans:
        _log_collection_op("orphan_candidate", cname)
    return orphans


def _find_orphan_segment_dirs() -> list[tuple[Path, int]]:
    """sqlite-vec has no HNSW segment dirs on disk; stub retained
    for call-site compatibility with _prune_orphan_segment_dirs."""
    return []


def _prune_orphan_segment_dirs(dry_run: bool = False) -> dict:
    """Delete orphan HNSW segment dirs. Returns {count, bytes_freed, paths}."""
    orphans = _find_orphan_segment_dirs()
    total = sum(sz for _, sz in orphans)
    out: dict = {
        "count": len(orphans),
        "bytes_freed": total,
        "paths": [p.name for p, _ in orphans],
    }
    if dry_run or not orphans:
        return out
    import shutil as _shutil
    removed = 0
    freed = 0
    for path, sz in orphans:
        try:
            _shutil.rmtree(path)
            removed += 1
            freed += sz
        except OSError:
            pass
    out["count"] = removed
    out["bytes_freed"] = freed
    return out


def _wal_checkpoint_for(sqlite_path: Path, *, dry_run: bool = False) -> dict:
    """Run `PRAGMA wal_checkpoint(TRUNCATE)` against an arbitrary sqlite file.

    Safer than VACUUM — doesn't require exclusive lock and truncates the
    write-ahead log after flushing. Returns {before_bytes, after_bytes, ok}.
    Helper for post-split maintenance: ragvec.db and telemetry.db each have
    their own WAL and need independent checkpoints.
    """
    wal_path = sqlite_path.with_suffix(sqlite_path.suffix + "-wal")
    if not sqlite_path.is_file():
        return {"ok": False, "reason": "no sqlite file"}
    before = sqlite_path.stat().st_size + (wal_path.stat().st_size if wal_path.is_file() else 0)
    if dry_run:
        return {"ok": True, "before_bytes": before, "after_bytes": before, "dry_run": True}
    import sqlite3 as _sqlite
    try:
        conn = _sqlite.connect(str(sqlite_path), timeout=5.0)
        try:
            conn.execute("PRAGMA wal_checkpoint(TRUNCATE)")
            conn.commit()
        finally:
            conn.close()
    except Exception as e:
        return {"ok": False, "reason": str(e), "before_bytes": before}
    after = sqlite_path.stat().st_size + (wal_path.stat().st_size if wal_path.is_file() else 0)
    return {"ok": True, "before_bytes": before, "after_bytes": after}


def _vec_wal_checkpoint(dry_run: bool = False) -> dict:
    """Run `PRAGMA wal_checkpoint(TRUNCATE)` on ragvec.db (sqlite-vec workload)."""
    return _wal_checkpoint_for(DB_PATH / "ragvec.db", dry_run=dry_run)


def _telemetry_wal_checkpoint(dry_run: bool = False) -> dict:
    """Run `PRAGMA wal_checkpoint(TRUNCATE)` on telemetry.db.

    Post 2026-04-21 split — telemetry.db is the hot-path writes target (queries,
    behavior, memory/cpu metrics). Separate WAL from ragvec.db, so an
    unconditional checkpoint is fired in run_maintenance to keep the WAL
    bounded even when --skip-logs bypasses _sql_rotate_log_tables.
    """
    return _wal_checkpoint_for(DB_PATH / _TELEMETRY_DB_FILENAME, dry_run=dry_run)


# ── SQL log rotation (T7) ────────────────────────────────────────────────────
# Retention policies per log-style rag_* table. When RAG_STATE_SQL=1 and
# `rag maintenance` runs, rows with ts < now - retention are DELETEd. State-
# style tables (rag_ambient_state, rag_brief_state, rag_conversations_index,
# rag_feedback_golden, rag_feedback_golden_meta) are keyed upserts and MUST
# NOT appear here.
#
# Defaults chosen in T7:
#   90d: queries, behavior             — ranker-vivo signal window
#   60d: ambient, brief_written, wa_tasks, archive, filing, eval, surface,
#        proactive — useful historic context but not ranker input
#   30d: cpu_metrics, memory_metrics, system_memory_metrics — sampled every
#        minute by the web sampler; bloat magnet otherwise
#   ∞ : feedback, tune, contradictions — small, high-signal, intentionally
#        kept (feedback golden depends on full rag_feedback history, tune
#        history feeds `rag dashboard`, contradictions are audit).
#
# Tables explicitly NOT rotated (empty tuple): retained forever.
_SQL_ROTATION_POLICY: tuple[tuple[str, int], ...] = (
    ("rag_queries", 90),
    ("rag_behavior", 90),
    ("rag_ambient", 60),
    ("rag_brief_written", 60),
    ("rag_wa_tasks", 60),
    ("rag_archive_log", 60),
    ("rag_filing_log", 60),
    ("rag_eval_runs", 60),
    ("rag_surface_log", 60),
    ("rag_proactive_log", 60),
    ("rag_cpu_metrics", 30),
    ("rag_memory_metrics", 30),
    ("system_memory_metrics", 30),
)

# Tables that upsert on a PK instead of appending log rows. Listed here both
# for the rollback DROP loop and as documentation of the no-rotate contract.
_SQL_STATE_TABLES: tuple[str, ...] = (
    "rag_ambient_state",
    "rag_brief_state",
    "rag_conversations_index",
    "rag_feedback_golden",
    "rag_feedback_golden_meta",
)

# Log-style tables that are kept forever (no rotation row). Auditable in
# `test_rotation_different_retentions_per_table` — their row count must not
# decrease after rotation.
_SQL_KEEP_ALL_TABLES: tuple[str, ...] = (
    "rag_feedback",
    "rag_tune",
    "rag_contradictions",
)

# VACUUM gate: page_count * page_size must exceed last_vacuum_size by this
# delta before we pay the cost. ~500 MB matches the T4 spec — VACUUM serialises
# the whole DB and should only run weekly at most.
_VACUUM_DELTA_BYTES = 500 * 1024 * 1024

# Key in rag_feedback_golden_meta for the last-vacuum sentinel. Reuses the
# existing meta table to avoid schema churn during the cutover; the key
# namespace ("vacuum_*") is disjoint from the feedback-golden keys.
_VACUUM_META_KEY_BYTES = "vacuum_last_bytes"
_VACUUM_META_KEY_TS = "vacuum_last_ts"


def _sql_rotate_log_tables(*, dry_run: bool = False,
                            now_ts: float | None = None) -> dict:
    """DELETE old rows from rotatable log tables + optionally VACUUM.

    Returns
    -------
    {
      "rows_deleted": {table: int, ...},
      "wal_checkpoint": {ok: bool, before_bytes: int, after_bytes: int},
      "vacuum_ran": bool,
      "vacuum_before_bytes": int | None,
      "vacuum_after_bytes": int | None,
    }

    Only touches rows matching the retention policy; state tables and
    keep-all tables are untouched. Safe under dry_run — no DELETE/VACUUM
    runs but the cutoff-derived counts are reported so operators can see
    what a live run would do.
    """
    import sqlite3 as _sqlite
    from datetime import datetime as _dt

    # Post 2026-04-21 split: rag_* log-style tables live in telemetry.db.
    sqlite_path = DB_PATH / _TELEMETRY_DB_FILENAME
    out: dict = {
        "rows_deleted": {},
        "wal_checkpoint": None,
        "vacuum_ran": False,
        "vacuum_before_bytes": None,
        "vacuum_after_bytes": None,
    }
    if not sqlite_path.is_file():
        out["skipped"] = "no sqlite file"
        return out

    # Use a dedicated connection — telemetry writers use short-lived conns
    # anyway, so briefly exclusive VACUUM can fight a writer. busy_timeout
    # is generous (30s) because rotation is unattended.
    now = now_ts if now_ts is not None else time.time()
    try:
        conn = _sqlite.connect(str(sqlite_path), timeout=30.0)
        conn.execute("PRAGMA busy_timeout=30000")
    except _sqlite.Error as e:
        out["skipped"] = f"connect failed: {e}"
        return out

    try:
        # Figure out which tables exist — skipping silently lets maintenance
        # run on a pre-T1 DB without crashing.
        existing = {
            r[0] for r in conn.execute(
                "SELECT name FROM sqlite_master WHERE type='table'"
            ).fetchall()
        }

        for table, days in _SQL_ROTATION_POLICY:
            if table not in existing:
                continue
            cutoff_iso = _dt.fromtimestamp(now - days * 86400).isoformat(
                timespec="seconds"
            )
            if dry_run:
                row = conn.execute(
                    f"SELECT COUNT(*) FROM {table} WHERE ts < ?", (cutoff_iso,)
                ).fetchone()
                out["rows_deleted"][table] = int(row[0] if row else 0)
            else:
                cur = conn.execute(
                    f"DELETE FROM {table} WHERE ts < ?", (cutoff_iso,)
                )
                out["rows_deleted"][table] = cur.rowcount or 0

        if not dry_run:
            conn.commit()

        # WAL checkpoint once after all deletes — cheaper than N checkpoints.
        # Post-split: telemetry.db-wal (not ragvec.db-wal).
        wal_path = DB_PATH / (_TELEMETRY_DB_FILENAME + "-wal")
        before_wal = sqlite_path.stat().st_size + (
            wal_path.stat().st_size if wal_path.is_file() else 0
        )
        if not dry_run:
            try:
                conn.execute("PRAGMA wal_checkpoint(TRUNCATE)")
                conn.commit()
                after_wal = sqlite_path.stat().st_size + (
                    wal_path.stat().st_size if wal_path.is_file() else 0
                )
                out["wal_checkpoint"] = {
                    "ok": True,
                    "before_bytes": before_wal,
                    "after_bytes": after_wal,
                }
            except _sqlite.Error as e:
                out["wal_checkpoint"] = {"ok": False, "reason": str(e)}
        else:
            out["wal_checkpoint"] = {
                "ok": True,
                "before_bytes": before_wal,
                "after_bytes": before_wal,
                "dry_run": True,
            }

        # Conditional VACUUM — gated by delta since last vacuum.
        page_count = int(conn.execute("PRAGMA page_count").fetchone()[0])
        page_size = int(conn.execute("PRAGMA page_size").fetchone()[0])
        current_bytes = page_count * page_size
        last_bytes_row = None
        if "rag_feedback_golden_meta" in existing:
            last_bytes_row = conn.execute(
                "SELECT v FROM rag_feedback_golden_meta WHERE k=?",
                (_VACUUM_META_KEY_BYTES,),
            ).fetchone()
        last_bytes = int(last_bytes_row[0]) if last_bytes_row and last_bytes_row[0] else 0
        delta = current_bytes - last_bytes
        should_vacuum = delta >= _VACUUM_DELTA_BYTES

        if should_vacuum and not dry_run:
            out["vacuum_before_bytes"] = current_bytes
            # VACUUM can't run inside a transaction.
            conn.isolation_level = None
            conn.execute("VACUUM")
            new_page_count = int(conn.execute("PRAGMA page_count").fetchone()[0])
            new_page_size = int(conn.execute("PRAGMA page_size").fetchone()[0])
            new_bytes = new_page_count * new_page_size
            out["vacuum_ran"] = True
            out["vacuum_after_bytes"] = new_bytes
            # Persist sentinel so we don't VACUUM again until another delta.
            if "rag_feedback_golden_meta" in existing:
                now_iso = _dt.fromtimestamp(now).isoformat(timespec="seconds")
                conn.execute(
                    "INSERT OR REPLACE INTO rag_feedback_golden_meta (k, v) VALUES (?, ?)",
                    (_VACUUM_META_KEY_BYTES, str(new_bytes)),
                )
                conn.execute(
                    "INSERT OR REPLACE INTO rag_feedback_golden_meta (k, v) VALUES (?, ?)",
                    (_VACUUM_META_KEY_TS, now_iso),
                )
                conn.commit()
        elif should_vacuum and dry_run:
            out["vacuum_ran"] = False
            out["vacuum_would_run"] = True
            out["vacuum_before_bytes"] = current_bytes
    finally:
        try:
            conn.close()
        except Exception:
            pass
    return out


def _cleanup_bak_files(*, dry_run: bool = False,
                        max_age_days: int = 30,
                        now_ts: float | None = None) -> dict:
    """Delete migration-era `*.bak.<unix_ts>` files older than max_age_days.

    T2's migration script renames each legacy source to `name.bak.<unix_ts>`.
    After the 30-day cutover observation window the originals are unneeded
    and just waste disk. We parse the unix ts suffix directly rather than
    stat — the filename IS the canonical migration time, stat.mtime can drift
    under rsync/iCloud/etc.

    Filenames that don't match `*.bak.<digits>` are ignored (including
    legacy `.bak`, `.bak.notanumber`, or user-created `.baktemp`).

    Returns
    -------
    {"deleted": int, "bytes_freed": int, "skipped_non_bak": int}
    """
    state_dir = Path.home() / ".local/share/obsidian-rag"
    out = {"deleted": 0, "bytes_freed": 0, "skipped_non_bak": 0}
    if not state_dir.is_dir():
        return out
    now = now_ts if now_ts is not None else time.time()
    cutoff = now - max_age_days * 86400
    for f in state_dir.iterdir():
        if not f.is_file():
            continue
        # Must match .*\.bak\.<digits>$
        name = f.name
        try:
            idx = name.rindex(".bak.")
        except ValueError:
            continue
        suffix = name[idx + len(".bak."):]
        if not suffix.isdigit():
            out["skipped_non_bak"] += 1
            continue
        try:
            file_ts = int(suffix)
        except ValueError:
            out["skipped_non_bak"] += 1
            continue
        if file_ts >= cutoff:
            continue  # still fresh
        try:
            size = f.stat().st_size
        except OSError:
            size = 0
        if dry_run:
            out["deleted"] += 1
            out["bytes_freed"] += size
        else:
            try:
                os.unlink(f)
                out["deleted"] += 1
                out["bytes_freed"] += size
            except OSError:
                continue
    return out


# ── Rollback subcommand helpers (T7) ─────────────────────────────────────────
# `rag maintenance --rollback-state-migration` restores the JSONL baseline
# in case the SQL cutover misbehaves within the 30-day observation window.
# The inverse of T2's migration: rename each `name.bak.<ts>` back to `name`,
# drop every rag_*/system_memory_metrics table, remove the schema_version
# rows, checkpoint the WAL + VACUUM.
#
# Safety: refuses to run when `com.fer.obsidian-rag-*` launchd services have
# live pids — a writer mid-transaction against a table we're about to drop
# would cause data loss. `--force` bypasses the service check and the no-bak
# refusal; it is NOT a free pass for the DROP TABLE loop which always runs.

_ROLLBACK_TABLES: tuple[str, ...] = tuple(
    name for name, _ in _TELEMETRY_DDL
)


def _pgrep_obsidian_rag() -> list[str]:
    """Return list of pids matching `com.fer.obsidian-rag` launchd services.

    Same logic as scripts/migrate_state_to_sqlite.py::_check_running_services
    but inlined here so maintenance doesn't import the migration script.
    """
    import subprocess as _sp
    try:
        out = _sp.run(
            ["pgrep", "-f", "com.fer.obsidian-rag"],
            capture_output=True, text=True, timeout=5,
        )
    except (_sp.TimeoutExpired, FileNotFoundError):
        return []
    if out.returncode != 0:
        return []
    return [line for line in out.stdout.split() if line.strip()]


def _find_bak_files_for_rollback(*, max_age_days: int = 30,
                                  now_ts: float | None = None) -> dict[str, Path]:
    """Scan state_dir for `.bak.<ts>` files newer than max_age_days.

    Returns a {original_path_as_str → newest_bak_path} mapping so the caller
    restores exactly one bak per source. When multiple baks exist (e.g. a
    user re-ran the migration twice) the most recent ts wins — the oldest
    baks represent an intermediate state we don't want to revert to.
    """
    state_dir = Path.home() / ".local/share/obsidian-rag"
    if not state_dir.is_dir():
        return {}
    now = now_ts if now_ts is not None else time.time()
    cutoff = now - max_age_days * 86400
    # source_path → (ts, bak_path) to pick newest-wins
    best: dict[str, tuple[int, Path]] = {}
    for f in state_dir.iterdir():
        if not f.is_file():
            continue
        name = f.name
        try:
            idx = name.rindex(".bak.")
        except ValueError:
            continue
        suffix = name[idx + len(".bak."):]
        if not suffix.isdigit():
            continue
        try:
            file_ts = int(suffix)
        except ValueError:
            continue
        if file_ts < cutoff:
            continue  # older than window — nothing to restore to
        original_name = name[:idx]
        prev = best.get(original_name)
        if prev is None or file_ts > prev[0]:
            best[original_name] = (file_ts, f)
    return {orig: p for orig, (_, p) in best.items()}


def _rollback_state_migration(*, force: bool = False,
                               now_ts: float | None = None) -> dict:
    """Restore .bak.<ts> originals + drop rag_* tables.

    Returns
    -------
    {
      "ok": bool,
      "refused": str | None,                # human reason, if refused
      "files_restored": int,
      "tables_dropped": list[str],
      "bytes_reclaimed": int,
      "wal_checkpoint": dict,
      "vacuum_before_bytes": int,
      "vacuum_after_bytes": int,
    }
    """
    import sqlite3 as _sqlite

    out: dict = {
        "ok": False,
        "refused": None,
        "files_restored": 0,
        "tables_dropped": [],
        "bytes_reclaimed": 0,
        "wal_checkpoint": None,
        "vacuum_before_bytes": None,
        "vacuum_after_bytes": None,
    }

    # 1. Preflight — services must be stopped.
    pids = _pgrep_obsidian_rag()
    if pids and not force:
        out["refused"] = (
            f"pgrep matched {len(pids)} com.fer.obsidian-rag pid(s): "
            f"{' '.join(pids)}. Stop launchd services or pass --force."
        )
        return out

    # 2. Preflight — at least one .bak.<ts> within the 30-day window must
    # exist, otherwise we're restoring nothing and DROPs would be lossy.
    bak_map = _find_bak_files_for_rollback(now_ts=now_ts)
    if not bak_map and not force:
        out["refused"] = (
            "No *.bak.<unix_ts> files found within the 30-day window. "
            "Nothing to restore to — pass --force to DROP tables anyway."
        )
        return out

    state_dir = Path.home() / ".local/share/obsidian-rag"

    # 3. Restore files. os.replace is atomic; if the original still exists
    # it's overwritten (expected — T3 writers may have been running in
    # dual-write mode or before the flag was flipped off).
    for original_name, bak_path in bak_map.items():
        dest = state_dir / original_name
        try:
            os.replace(bak_path, dest)
            out["files_restored"] += 1
        except OSError as e:
            _log_sql_state_error("rollback_restore_failed",
                                  src=str(bak_path), dst=str(dest), err=repr(e))

    # 4. DROP rag_* tables in one transaction + clear schema_version rows.
    # Post 2026-04-21 split: rag_* tables now live in telemetry.db, not
    # ragvec.db. Rollback drops from the new file. If the operator is
    # rolling back to a pre-split checkpoint they should `git revert`
    # first (per CLAUDE.md rollback procedure), which restores the old
    # code that re-reads ragvec.db.
    sqlite_path = DB_PATH / _TELEMETRY_DB_FILENAME
    if sqlite_path.is_file():
        wal_path = DB_PATH / (_TELEMETRY_DB_FILENAME + "-wal")
        before_bytes = sqlite_path.stat().st_size + (
            wal_path.stat().st_size if wal_path.is_file() else 0
        )
        try:
            conn = _sqlite.connect(str(sqlite_path), timeout=30.0)
            conn.execute("PRAGMA busy_timeout=30000")
        except _sqlite.Error as e:
            out["refused"] = f"connect failed: {e}"
            return out
        try:
            existing = {
                r[0] for r in conn.execute(
                    "SELECT name FROM sqlite_master WHERE type='table'"
                ).fetchall()
            }
            conn.execute("BEGIN")
            dropped: list[str] = []
            for t in _ROLLBACK_TABLES:
                if t in existing:
                    conn.execute(f"DROP TABLE IF EXISTS {t}")
                    dropped.append(t)
            # Remove schema_version entries for the dropped tables.
            if "rag_schema_version" in existing and dropped:
                conn.executemany(
                    "DELETE FROM rag_schema_version WHERE table_name=?",
                    [(t,) for t in dropped],
                )
            conn.execute("COMMIT")
            out["tables_dropped"] = dropped

            # Checkpoint + VACUUM to reclaim pages. VACUUM rebuilds the db
            # file so the tables actually release their pages (DROP alone
            # only marks pages as free).
            conn.execute("PRAGMA wal_checkpoint(TRUNCATE)")
            conn.commit()
            # Sentinel: re-read size BEFORE vacuum so the reclaim metric
            # reflects the DROP+VACUUM combo, not just WAL truncation.
            out["vacuum_before_bytes"] = sqlite_path.stat().st_size
            conn.isolation_level = None
            conn.execute("VACUUM")
            out["vacuum_after_bytes"] = sqlite_path.stat().st_size
            out["wal_checkpoint"] = {"ok": True,
                                       "before_bytes": before_bytes,
                                       "after_bytes": sqlite_path.stat().st_size}
        except _sqlite.Error as e:
            try:
                conn.execute("ROLLBACK")
            except Exception:
                pass
            out["refused"] = f"sqlite error: {e}"
            return out
        finally:
            try:
                conn.close()
            except Exception:
                pass
        after_bytes = sqlite_path.stat().st_size + (
            wal_path.stat().st_size if wal_path.is_file() else 0
        )
        out["bytes_reclaimed"] = max(0, before_bytes - after_bytes)

    out["ok"] = True
    return out


def run_maintenance(
    *,
    dry_run: bool = False,
    skip_reindex: bool = False,
    skip_logs: bool = False,
    verbose: bool = False,
) -> dict:
    """Run all maintenance tasks. Returns summary dict."""
    import time as _t
    t0 = _t.perf_counter()
    results: dict = {}

    # 1. Incremental reindex (cleans orphan chunks too)
    if not skip_reindex and not dry_run:
        try:
            idx = auto_index_vault(VAULT_PATH)
            results["reindex"] = idx
        except Exception as e:
            results["reindex_error"] = str(e)

    # 2. Session cleanup
    removed_sessions = cleanup_sessions()
    results["sessions_removed"] = removed_sessions

    # 3. Orphan collections
    orphan_cols = _find_orphan_collections()
    results["orphan_collections"] = orphan_cols
    if orphan_cols and not dry_run:
        with _collection_write_lock():
            client = SqliteVecClient(path=str(DB_PATH))
            for cname in orphan_cols:
                try:
                    _log_collection_op("delete", cname, {"reason": "run_maintenance orphan"})
                    client.delete_collection(cname)
                except Exception:
                    pass
        results["orphan_collections_removed"] = len(orphan_cols)

    # 3b. Orphan segment dirs stub (sqlite-vec stores all data in ragvec.db; no dirs)
    try:
        results["orphan_segments"] = _prune_orphan_segment_dirs(dry_run=dry_run)
    except Exception as e:
        results["orphan_segments_error"] = str(e)

    # 3c. WAL checkpoint — post-split we have two files with two WALs.
    # ragvec.db-wal compacts here; telemetry.db-wal compacts inside
    # _sql_rotate_log_tables (step 8) so it's always covered when logs
    # run, and we also fire an unconditional telemetry checkpoint below
    # so --skip-logs doesn't starve it.
    try:
        results["wal_checkpoint"] = _vec_wal_checkpoint(dry_run=dry_run)
    except Exception as e:
        results["wal_checkpoint_error"] = str(e)
    try:
        results["wal_checkpoint_telemetry"] = _telemetry_wal_checkpoint(dry_run=dry_run)
    except Exception as e:
        results["wal_checkpoint_telemetry_error"] = str(e)

    # 4. Context cache pruning
    try:
        col = get_db()
        if dry_run:
            cache = _load_context_cache()
            sq_cache = _load_synthetic_q_cache()
            existing = col.get(include=["metadatas"])
            live_hashes = {m.get("hash", "") for m in existing["metadatas"]} - {""}
            results["context_cache_pruned"] = sum(1 for k in cache if k not in live_hashes)
            results["synthetic_q_cache_pruned"] = sum(1 for k in sq_cache if k not in live_hashes)
        else:
            pruned = _prune_context_cache(col)
            results["context_cache_pruned"] = pruned
            pruned_sq = _prune_synthetic_q_cache(col)
            results["synthetic_q_cache_pruned"] = pruned_sq
    except Exception as e:
        results["context_cache_error"] = str(e)

    # 5. Feedback golden rebuild (SQL-only since T10).
    if not dry_run:
        try:
            with _ragvec_state_conn() as conn:
                golden = _rebuild_feedback_golden_from_sql_feedback(conn)
            results["feedback_golden"] = {
                "positives": len(golden.get("positives", [])),
                "negatives": len(golden.get("negatives", [])),
            }
        except Exception as e:
            results["feedback_golden_error"] = str(e)

    # 6. Log rotation.
    # When RAG_STATE_SQL=1 the JSONL files are no-longer written (T3 swap),
    # so we run SQL-aware rotation against the rag_* tables + clean up the
    # one-shot `.bak.<ts>` migration artefacts. When the flag is off we keep
    # the legacy JSONL rotation path unchanged.
    if not skip_logs:
        if RAG_STATE_SQL:
            try:
                results["sql_rotation"] = _sql_rotate_log_tables(dry_run=dry_run)
            except Exception as e:
                results["sql_rotation_error"] = str(e)
            try:
                results["bak_cleanup"] = _cleanup_bak_files(dry_run=dry_run)
            except Exception as e:
                results["bak_cleanup_error"] = str(e)
            # Keep JSONL rotation section empty for renderer compatibility so
            # downstream callers that already branch on "log_rotation" don't
            # explode when the flag is on.
            results["log_rotation"] = {}
        else:
            rotated = {}
            for label, path in _JSONL_LOG_PATHS:
                if dry_run:
                    try:
                        sz = path.stat().st_size if path.is_file() else 0
                        if sz >= _JSONL_ROTATE_BYTES:
                            rotated[label] = f"would rotate ({sz / 1024:.0f} KB)"
                    except OSError:
                        pass
                else:
                    r = _rotate_jsonl(path)
                    if r:
                        rotated[label] = r
            results["log_rotation"] = rotated

    # 7. Ignored notes orphans
    if dry_run:
        ign = load_ignored_paths()
        results["ignored_pruned"] = sum(1 for p in ign if not (VAULT_PATH / p).exists())
    else:
        results["ignored_pruned"] = _prune_ignored_notes(VAULT_PATH)

    # 8. Auto-index state orphans
    if dry_run:
        st = _auto_index_state_load()
        valid = {_vault_state_key(VAULT_PATH)}
        try:
            vcfg = _load_vaults_config()
            for vp in vcfg["vaults"].values():
                valid.add(_vault_state_key(Path(vp)))
        except Exception:
            pass
        results["index_state_pruned"] = sum(1 for k in st if k not in valid)
    else:
        results["index_state_pruned"] = _prune_auto_index_state()

    # 9. Filing batch pruning (>90d)
    if dry_run:
        cutoff = _t.time() - _FILING_BATCH_TTL_DAYS * 86400
        results["batches_pruned"] = sum(
            1 for f in (FILING_BATCHES_DIR.glob("*.jsonl") if FILING_BATCHES_DIR.is_dir() else [])
            if f.stat().st_mtime < cutoff
        )
    else:
        results["batches_pruned"] = _prune_filing_batches()

    # 10. Tmp file cleanup
    if dry_run:
        state_dir = Path.home() / ".local/share/obsidian-rag"
        n_tmp = 0
        for d in (state_dir, SESSIONS_DIR):
            if d.is_dir():
                n_tmp += sum(1 for t in d.glob("*.tmp") if _t.time() - t.stat().st_mtime > 3600)
        results["tmp_cleaned"] = n_tmp
    else:
        results["tmp_cleaned"] = _cleanup_tmp_files()

    # 11. URL orphans (files deleted but URL rows remain)
    if dry_run:
        try:
            cu = get_urls_db()
            all_u = cu.get(include=["metadatas"])
            od = {
                str(p.relative_to(VAULT_PATH))
                for p in VAULT_PATH.rglob("*.md")
                if not is_excluded(str(p.relative_to(VAULT_PATH)))
            }
            results["url_orphans"] = sum(
                1 for m in all_u["metadatas"] if m.get("file", "") not in od
            )
        except Exception:
            results["url_orphans"] = 0
    else:
        results["url_orphans"] = _prune_url_orphans(VAULT_PATH)

    # 12. Feedback orphans (paths no longer in vault)
    if dry_run:
        try:
            od = {
                str(p.relative_to(VAULT_PATH))
                for p in VAULT_PATH.rglob("*.md")
                if not is_excluded(str(p.relative_to(VAULT_PATH)))
            }
            n_fb_orphan = 0
            if FEEDBACK_PATH.is_file():
                for line in FEEDBACK_PATH.read_text(encoding="utf-8").splitlines():
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        ev = json.loads(line)
                    except Exception:
                        continue
                    paths = ev.get("paths") or []
                    if paths and not any(p in od for p in paths):
                        n_fb_orphan += 1
            results["feedback_orphans"] = n_fb_orphan
        except Exception:
            results["feedback_orphans"] = 0
    else:
        results["feedback_orphans"] = _prune_feedback_orphans(VAULT_PATH)

    # 13. Ollama health (read-only)
    results["ollama"] = _check_ollama_health()

    # 14. Dead notes count (read-only)
    try:
        col = get_db()
        dead = find_dead_notes(col, VAULT_PATH, LOG_PATH)
        results["dead_notes"] = len(dead)
    except Exception:
        results["dead_notes"] = 0

    results["took_ms"] = int((_t.perf_counter() - t0) * 1000)
    return results


# ── Cutover validation (T10 pre-strip gate) ──────────────────────────────────
# Before T10 flips RAG_STATE_SQL to default-on + strips the JSONL fallback,
# we want a read-only way to verify every source migrated cleanly. The
# migration script renames each JSONL to <name>.bak.<unix_ts> on success;
# this helper walks the SOURCES map and compares SQL COUNT(*) vs JSONL
# line count. SQL ≥ JSONL = OK (post-cutover activity accumulated on top).
# SQL < JSONL = FAIL (lost rows — abort the strip).

_CUTOVER_SOURCES: tuple[tuple[str, str], ...] = (
    # (jsonl_filename, sql_table)
    ("queries.jsonl", "rag_queries"),
    ("behavior.jsonl", "rag_behavior"),
    ("feedback.jsonl", "rag_feedback"),
    ("tune.jsonl", "rag_tune"),
    ("contradictions.jsonl", "rag_contradictions"),
    ("ambient.jsonl", "rag_ambient"),
    ("brief_written.jsonl", "rag_brief_written"),
    ("wa_tasks.jsonl", "rag_wa_tasks"),
    ("archive.jsonl", "rag_archive_log"),
    ("filing.jsonl", "rag_filing_log"),
    ("eval.jsonl", "rag_eval_runs"),
    ("surface.jsonl", "rag_surface_log"),
    ("proactive.jsonl", "rag_proactive_log"),
    ("rag_cpu.jsonl", "rag_cpu_metrics"),
    ("rag_memory.jsonl", "rag_memory_metrics"),
    ("system_memory.jsonl", "system_memory_metrics"),
    # state_latest_jsonl sources (upsert-style: SQL rows ≤ JSONL lines
    # because repeated keys collapse on write). WARN if SQL < unique-key
    # count, don't fail on raw count mismatch.
    ("ambient_state.jsonl", "rag_ambient_state"),
    ("brief_state.jsonl", "rag_brief_state"),
)


def _count_jsonl_lines(path: Path) -> int:
    """Count non-blank lines in a JSONL. Tolerates missing file → 0."""
    if not path.is_file():
        return 0
    try:
        with path.open("rb") as f:
            # Binary read avoids decoding a giant log we only want to
            # line-count. Filter blanks so trailing newline doesn't add 1.
            return sum(1 for line in f if line.strip())
    except OSError:
        return 0


def _validate_cutover_state() -> list[dict]:
    """Read-only audit comparing SQL row counts vs source JSONL line counts.

    For each (jsonl, table) in _CUTOVER_SOURCES:
      1. Find the newest <jsonl>.bak.<ts> in ~/.local/share/obsidian-rag/.
      2. Count lines in it.
      3. Run `SELECT COUNT(*) FROM <table>` in ragvec.db.
      4. Compute delta_pct = (sql - bak) / bak * 100 (0 if bak empty).
      5. status: "ok" if sql >= bak, "warn" if sql within -1% of bak,
         "fail" if sql < -1% of bak, "no_bak" if no .bak file exists.

    Returns a list of dicts; caller decides rendering and exit code.
    Never raises — individual source errors captured in the result.
    """
    state_dir = Path.home() / ".local/share/obsidian-rag"
    results: list[dict] = []
    for jsonl_name, table in _CUTOVER_SOURCES:
        entry: dict = {"source": jsonl_name, "table": table}
        # Find the newest .bak.<unix_ts>. sorted() is stable and the
        # unix timestamp suffix gives a chronological order.
        baks = sorted(state_dir.glob(f"{jsonl_name}.bak.*"))
        if not baks:
            entry.update({
                "status": "no_bak",
                "bak_lines": None,
                "sql_rows": None,
                "delta_pct": None,
            })
            results.append(entry)
            continue
        bak = baks[-1]
        bak_lines = _count_jsonl_lines(bak)
        # SQL count
        try:
            if not RAG_STATE_SQL:
                # Feature flag off = table either empty or never created.
                # Still report, but flag so the user knows why SQL=0.
                entry.update({
                    "status": "flag_off",
                    "bak_lines": bak_lines,
                    "sql_rows": None,
                    "delta_pct": None,
                    "bak_file": bak.name,
                })
                results.append(entry)
                continue
            with _ragvec_state_conn() as conn:
                row = conn.execute(
                    f"SELECT COUNT(*) FROM {table}"  # noqa: S608 - hardcoded table list
                ).fetchone()
                sql_rows = int(row[0]) if row else 0
        except Exception as exc:
            entry.update({
                "status": "sql_err",
                "err": repr(exc)[:200],
                "bak_lines": bak_lines,
                "sql_rows": None,
                "delta_pct": None,
                "bak_file": bak.name,
            })
            results.append(entry)
            continue
        delta_pct = ((sql_rows - bak_lines) / bak_lines * 100.0) if bak_lines else 0.0
        if sql_rows >= bak_lines:
            status = "ok"
        elif delta_pct >= -1.0:
            # Within 1% — tolerated (migration drops malformed rows; see
            # migrate_state_to_sqlite.py comments on 43 pre-existing bad
            # rows dropped during the 2026-04-19 cutover).
            status = "warn"
        else:
            status = "fail"
        entry.update({
            "status": status,
            "bak_lines": bak_lines,
            "sql_rows": sql_rows,
            "delta_pct": round(delta_pct, 2),
            "bak_file": bak.name,
        })
        results.append(entry)
    return results


def _render_cutover_validation(results: list[dict]) -> None:
    """Pretty-print the cutover validation table to the console."""
    console.print(Rule(title="[bold cyan]Cutover validation[/bold cyan]", style="cyan"))
    tbl = Table(show_lines=False)
    tbl.add_column("source", style="cyan", no_wrap=True)
    tbl.add_column("table", style="dim", no_wrap=True)
    tbl.add_column("bak lines", justify="right")
    tbl.add_column("SQL rows", justify="right")
    tbl.add_column("Δ%", justify="right")
    tbl.add_column("status", no_wrap=True)
    status_styles = {
        "ok": "green", "warn": "yellow", "fail": "red",
        "no_bak": "dim", "sql_err": "red", "flag_off": "dim yellow",
    }
    for r in results:
        status = r.get("status", "?")
        style = status_styles.get(status, "white")
        bak = r.get("bak_lines")
        sql = r.get("sql_rows")
        delta = r.get("delta_pct")
        tbl.add_row(
            r.get("source", "?"),
            r.get("table", "?"),
            "-" if bak is None else f"{bak:,}",
            "-" if sql is None else f"{sql:,}",
            "-" if delta is None else f"{delta:+.2f}%",
            f"[{style}]{status}[/{style}]",
        )
    console.print(tbl)
    fails = [r for r in results if r.get("status") == "fail"]
    warns = [r for r in results if r.get("status") == "warn"]
    if fails:
        console.print(
            f"[red]✗ {len(fails)} source(s) regressed — SQL has FEWER rows than "
            f"the .bak. DO NOT strip the JSONL fallback yet.[/red]"
        )
    elif warns:
        console.print(
            f"[yellow]⚠ {len(warns)} source(s) within 1% delta — acceptable "
            f"(migration drops malformed rows) but worth noting.[/yellow]"
        )
    else:
        console.print("[green]✓ All sources: SQL ≥ JSONL — safe to proceed with T10 strip.[/green]")


@cli.command()
@click.option("--dry-run", is_flag=True, help="Reportar sin modificar nada")
@click.option("--skip-reindex", is_flag=True, help="Saltear reindex incremental")
@click.option("--skip-logs", is_flag=True, help="Saltear rotación de logs")
@click.option("--verbose", "-v", is_flag=True, help="Mostrar detalles de cada paso")
@click.option("--json", "as_json", is_flag=True, help="Output JSON (para cron/scripts)")
@click.option("--rollback-state-migration", "rollback_state", is_flag=True,
               help="Escape hatch: restaurar .bak.<ts> originales + dropear rag_* tables (T7)")
@click.option("--validate-cutover", "validate_cutover", is_flag=True,
               help="Read-only: comparar COUNT(*) de cada rag_* table vs líneas en su .bak.<ts> (pre-T10 gate)")
@click.option("--force", is_flag=True,
               help="Bypass safety gates en --rollback-state-migration")
def maintenance(dry_run: bool, skip_reindex: bool, skip_logs: bool, verbose: bool,
                 as_json: bool, rollback_state: bool, validate_cutover: bool,
                 force: bool):
    """Mantenimiento integral: reindex, limpiar sesiones, podar caches, rotar logs, detectar dead notes.

    Seguro para correr periódicamente vía launchd/cron. Con --dry-run solo reporta.

    --rollback-state-migration deshace T2: renombra cada `.bak.<unix_ts>` a su
    nombre original + dropea las 21 rag_*/system_memory_metrics tables +
    VACUUM. Refuses si hay launchd services corriendo (usa --force para
    bypass) o si no hay .bak.<ts> dentro de la ventana de 30 días.

    --validate-cutover compara COUNT(*) de cada rag_* table con el line count
    del `.bak.<ts>` más reciente del JSONL que migró. Read-only, seguro en
    vivo. Propósito: gate pre-T10 — si algún delta es negativo (SQL < JSONL),
    significa que la migración perdió filas y NO se debe strippear el
    fallback. Útil en cron diario durante la ventana de observación.
    """
    if validate_cutover:
        results = _validate_cutover_state()
        if as_json:
            click.echo(json.dumps(results, ensure_ascii=False, indent=2))
            return
        _render_cutover_validation(results)
        # Non-zero exit if any source regressed (SQL < JSONL).
        if any(r.get("status") == "fail" for r in results):
            raise SystemExit(1)
        return
    if rollback_state:
        if not as_json:
            mode = "[yellow]DRY RUN[/yellow]" if dry_run else "[red]ROLLBACK[/red]"
            console.print(Rule(title=f"[bold cyan]State Migration Rollback[/bold cyan] {mode}",
                                style="cyan"))
            console.print()
        if dry_run:
            # Dry-run semantics: report what the rollback would touch without
            # renaming or dropping anything.
            pids = _pgrep_obsidian_rag()
            bak_map = _find_bak_files_for_rollback()
            summary = {
                "would_refuse": bool(pids and not force) or (not bak_map and not force),
                "running_pids": pids,
                "bak_files_found": len(bak_map),
                "tables_would_drop": [t for t in _ROLLBACK_TABLES],
            }
            if as_json:
                click.echo(json.dumps(summary, ensure_ascii=False, indent=2, default=str))
                return
            if summary["would_refuse"]:
                if pids and not force:
                    console.print(f"  [red]Refused:[/red] {len(pids)} launchd service(s) running — "
                                   "stop services or pass --force.")
                if not bak_map and not force:
                    console.print("  [red]Refused:[/red] no .bak.<unix_ts> files within 30-day window — "
                                   "nothing to restore to (pass --force to DROP anyway).")
            console.print(f"  [bold].bak.<ts> files:[/bold] {len(bak_map)} would be restored")
            console.print(f"  [bold]Tables would drop:[/bold] {len(summary['tables_would_drop'])}")
            return
        result = _rollback_state_migration(force=force)
        if as_json:
            click.echo(json.dumps(result, ensure_ascii=False, indent=2, default=str))
            return
        if not result["ok"]:
            console.print(f"  [red]Refused:[/red] {result.get('refused', 'unknown')}")
            raise click.exceptions.Exit(1)
        mb = result.get("bytes_reclaimed", 0) / (1024 * 1024)
        console.print(f"  [bold]Files restored:[/bold] {result['files_restored']}")
        console.print(f"  [bold]Tables dropped:[/bold] {len(result['tables_dropped'])}"
                       f" [dim]({', '.join(result['tables_dropped'][:4])}"
                       f"{', …' if len(result['tables_dropped']) > 4 else ''})[/dim]")
        console.print(f"  [bold]Disk reclaimed:[/bold] {mb:.1f} MB")
        return

    if not as_json:
        mode = "[yellow]DRY RUN[/yellow]" if dry_run else "[green]LIVE[/green]"
        console.print(Rule(title=f"[bold cyan]Maintenance[/bold cyan] {mode}", style="cyan"))
        console.print()

    results = run_maintenance(
        dry_run=dry_run,
        skip_reindex=skip_reindex,
        skip_logs=skip_logs,
        verbose=verbose,
    )

    if as_json:
        click.echo(json.dumps(results, ensure_ascii=False, indent=2, default=str))
        return

    # ── Reindex ──
    idx = results.get("reindex")
    if idx:
        kind = idx.get("kind", "?")
        color = {"no_changes": "dim", "incremental": "green", "first_time": "yellow"}.get(kind, "white")
        console.print(f"  [bold]Reindex:[/bold] [{color}]{kind}[/{color}]"
                      f" — {idx.get('indexed', 0)} indexed, {idx.get('removed', 0)} orphans removed"
                      f" [dim]({idx.get('scanned', 0)} scanned, {idx.get('took_ms', 0)}ms)[/dim]")
    elif "reindex_error" in results:
        console.print(f"  [bold]Reindex:[/bold] [red]error: {results['reindex_error']}[/red]")
    else:
        console.print("  [bold]Reindex:[/bold] [dim]skipped[/dim]")

    # ── Sessions ──
    n_sess = results.get("sessions_removed", 0)
    console.print(f"  [bold]Sessions:[/bold] {n_sess} expired removed" if n_sess else
                  "  [bold]Sessions:[/bold] [dim]none expired[/dim]")

    # ── Orphan collections ──
    orphans = results.get("orphan_collections", [])
    if orphans:
        action = "would remove" if dry_run else "removed"
        console.print(f"  [bold]Orphan collections:[/bold] [yellow]{action} {len(orphans)}[/yellow]: {', '.join(orphans)}")
    else:
        console.print("  [bold]Orphan collections:[/bold] [dim]none[/dim]")

    # ── Orphan segment dirs ──
    seg = results.get("orphan_segments") or {}
    n_seg = seg.get("count", 0)
    if n_seg:
        verb = "would free" if dry_run else "freed"
        mb = seg.get("bytes_freed", 0) / (1024 * 1024)
        console.print(f"  [bold]Orphan segments:[/bold] [yellow]{n_seg} dirs, {verb} {mb:.0f} MB[/yellow]")
    else:
        console.print("  [bold]Orphan segments:[/bold] [dim]none[/dim]")

    # ── WAL checkpoint ──
    wal = results.get("wal_checkpoint") or {}
    if wal.get("ok"):
        b = wal.get("before_bytes", 0) / (1024 * 1024)
        a = wal.get("after_bytes", 0) / (1024 * 1024)
        if dry_run:
            console.print(f"  [bold]WAL:[/bold] [dim]{b:.1f} MB (dry-run)[/dim]")
        else:
            console.print(f"  [bold]WAL:[/bold] checkpoint {b:.1f} → {a:.1f} MB")
    elif "wal_checkpoint_error" in results or wal.get("reason"):
        reason = results.get("wal_checkpoint_error") or wal.get("reason")
        console.print(f"  [bold]WAL:[/bold] [dim red]skipped: {reason}[/dim red]")

    # ── Context cache ──
    pruned = results.get("context_cache_pruned", 0)
    if pruned:
        verb = "would prune" if dry_run else "pruned"
        console.print(f"  [bold]Context cache:[/bold] [yellow]{pruned} stale entries {verb}[/yellow]")
    else:
        console.print("  [bold]Context cache:[/bold] [dim]clean[/dim]")

    # ── Feedback golden ──
    fg = results.get("feedback_golden")
    if fg:
        console.print(f"  [bold]Feedback golden:[/bold] rebuilt ({fg['positives']}+ / {fg['negatives']}-)")
    elif dry_run:
        console.print("  [bold]Feedback golden:[/bold] [dim]skipped (dry-run)[/dim]")

    # ── Log rotation ──
    rotated = results.get("log_rotation", {})
    if rotated:
        for label, detail in rotated.items():
            console.print(f"  [bold]Log rotation:[/bold] {label} — {detail}")
    elif not RAG_STATE_SQL:
        console.print("  [bold]Log rotation:[/bold] [dim]all under threshold[/dim]")

    # ── SQL log rotation (flag ON) ──
    sql_rot = results.get("sql_rotation") or {}
    if sql_rot:
        rows = sql_rot.get("rows_deleted", {}) or {}
        total = sum(rows.values())
        verb = "would delete" if dry_run else "deleted"
        if total:
            console.print(f"  [bold]SQL rotation:[/bold] [yellow]{verb} {total} rows[/yellow] "
                           f"across {sum(1 for v in rows.values() if v)} tables")
            if verbose:
                for t, n in sorted(rows.items(), key=lambda x: -x[1]):
                    if n:
                        console.print(f"    [dim]{t}: {n}[/dim]")
        else:
            console.print("  [bold]SQL rotation:[/bold] [dim]no rows past retention[/dim]")
        wal = sql_rot.get("wal_checkpoint") or {}
        if wal.get("ok"):
            b = wal.get("before_bytes", 0) / (1024 * 1024)
            a = wal.get("after_bytes", 0) / (1024 * 1024)
            if dry_run:
                console.print(f"  [bold]SQL WAL:[/bold] [dim]{b:.1f} MB (dry-run)[/dim]")
            else:
                console.print(f"  [bold]SQL WAL:[/bold] checkpoint {b:.1f} → {a:.1f} MB")
        if sql_rot.get("vacuum_ran"):
            bv = (sql_rot.get("vacuum_before_bytes") or 0) / (1024 * 1024)
            av = (sql_rot.get("vacuum_after_bytes") or 0) / (1024 * 1024)
            console.print(f"  [bold]VACUUM:[/bold] ran {bv:.1f} → {av:.1f} MB")
        elif sql_rot.get("vacuum_would_run"):
            console.print("  [bold]VACUUM:[/bold] [yellow]would run (delta ≥ 500 MB)[/yellow]")
        else:
            console.print("  [bold]VACUUM:[/bold] [dim]skipped (delta < 500 MB)[/dim]")
    elif "sql_rotation_error" in results:
        console.print(f"  [bold]SQL rotation:[/bold] [red]error: {results['sql_rotation_error']}[/red]")

    # ── Migration .bak cleanup ──
    bak = results.get("bak_cleanup") or {}
    if bak:
        n = bak.get("deleted", 0)
        mb = bak.get("bytes_freed", 0) / (1024 * 1024)
        if n:
            verb = "would purge" if dry_run else "purged"
            console.print(f"  [bold].bak cleanup:[/bold] [yellow]{verb} {n} files ({mb:.1f} MB)[/yellow]")
        else:
            console.print("  [bold].bak cleanup:[/bold] [dim]none >30d[/dim]")

    # ── Ignored notes ──
    ign = results.get("ignored_pruned", 0)
    if ign:
        verb = "would prune" if dry_run else "pruned"
        console.print(f"  [bold]Ignored notes:[/bold] [yellow]{ign} stale entries {verb}[/yellow]")
    else:
        console.print("  [bold]Ignored notes:[/bold] [dim]clean[/dim]")

    # ── Auto-index state ──
    idx_st = results.get("index_state_pruned", 0)
    if idx_st:
        verb = "would prune" if dry_run else "pruned"
        console.print(f"  [bold]Index state:[/bold] [yellow]{idx_st} orphan vault keys {verb}[/yellow]")
    else:
        console.print("  [bold]Index state:[/bold] [dim]clean[/dim]")

    # ── Filing batches ──
    batches = results.get("batches_pruned", 0)
    if batches:
        verb = "would prune" if dry_run else "pruned"
        console.print(f"  [bold]Filing batches:[/bold] [yellow]{batches} old batches {verb}[/yellow] [dim](>{_FILING_BATCH_TTL_DAYS}d)[/dim]")
    else:
        console.print("  [bold]Filing batches:[/bold] [dim]none expired[/dim]")

    # ── Tmp files ──
    tmps = results.get("tmp_cleaned", 0)
    if tmps:
        verb = "would remove" if dry_run else "removed"
        console.print(f"  [bold]Tmp files:[/bold] [yellow]{tmps} orphans {verb}[/yellow]")
    else:
        console.print("  [bold]Tmp files:[/bold] [dim]none[/dim]")

    # ── URL orphans ──
    url_orph = results.get("url_orphans", 0)
    if url_orph:
        verb = "would prune" if dry_run else "pruned"
        console.print(f"  [bold]URL orphans:[/bold] [yellow]{url_orph} rows {verb}[/yellow]")
    else:
        console.print("  [bold]URL orphans:[/bold] [dim]clean[/dim]")

    # ── Feedback orphans ──
    fb_orph = results.get("feedback_orphans", 0)
    if fb_orph:
        verb = "would prune" if dry_run else "pruned"
        console.print(f"  [bold]Feedback orphans:[/bold] [yellow]{fb_orph} stale entries {verb}[/yellow]")
    else:
        console.print("  [bold]Feedback orphans:[/bold] [dim]clean[/dim]")

    # ── Ollama health ──
    oll = results.get("ollama", {})
    if "error" in oll:
        console.print(f"  [bold]Ollama:[/bold] [red]unreachable: {oll['error']}[/red]")
    else:
        missing = [m for m, s in oll.items() if s == "missing"]
        if missing:
            console.print(f"  [bold]Ollama:[/bold] [red]missing: {', '.join(missing)}[/red]")
        else:
            console.print(f"  [bold]Ollama:[/bold] [green]{len(oll)} models ok[/green]")

    # ── Dead notes ──
    dead = results.get("dead_notes", 0)
    if dead:
        console.print(f"  [bold]Dead notes:[/bold] [yellow]{dead} candidates[/yellow] [dim](run `rag archive` to act)[/dim]")
    else:
        console.print("  [bold]Dead notes:[/bold] [dim]none[/dim]")

    console.print()
    console.print(f"  [dim]Done in {results.get('took_ms', 0)}ms[/dim]")


# ── UNIFIED PENDIENTES DASHBOARD (rag pendientes) ───────────────────────────
# Single mid-day view combining every "awaiting my attention" signal across
# the integrations: Gmail awaiting-reply + Apple Mail unread + WhatsApp chats
# sin responder + Reminders overdue/today/undated + vault followup loops +
# new contradictions + today's calendar + low-confidence queries.
#
# Morning brief already touches these but dispersed across sections and
# diluted by the LLM narrative. `rag pendientes` is code-owned, deterministic,
# fast (<3s on warm caches, no LLM call) — designed for a mid-day check-in.


def _pendientes_collect(col, now: datetime, days: int) -> dict:
    """Pure evidence collection — caller renders. Easier to test.

    Fetches dispatch concurrently via ThreadPoolExecutor: each source is
    independent I/O (osascript, subprocess, SQLite, HTTP, file reads) so the
    GIL releases during each call and 9 ~1s fetches drop from ~10s serial
    to the slowest single fetch (~2s). Per-future silent-fail preserved.
    """
    from concurrent.futures import ThreadPoolExecutor, as_completed

    stale_days = 14

    def _loops() -> dict:
        loops_all = _pendientes_extract_loops_fast(VAULT_PATH, days=days, max_items=40)
        loops_all.sort(key=lambda x: x.get("age_days", 0), reverse=True)
        return {
            "loops_stale": [x for x in loops_all if x.get("age_days", 0) >= stale_days][:5],
            "loops_activo": [x for x in loops_all if x.get("age_days", 0) < stale_days][:5],
        }

    tasks: dict[str, callable] = {
        "mail_unread":    _fetch_mail_unread,
        "reminders":      lambda: _fetch_reminders_due(now, horizon_days=1, max_items=30),
        "calendar":       _fetch_calendar_today,
        "whatsapp":       lambda: _fetch_whatsapp_unread(hours=24, max_chats=8),
        "weather":        _fetch_weather_rain,
        "gmail":          lambda: _fetch_gmail_evidence(now),
        "loops":          _loops,
        "contradictions": lambda: _pendientes_recent_contradictions(
            CONTRADICTION_LOG_PATH, now, days=days,
        ),
        "low_conf":       lambda: _pendientes_low_conf_queries(LOG_PATH, now, days=days),
    }

    ev: dict = {}
    with ThreadPoolExecutor(max_workers=len(tasks), thread_name_prefix="pendientes") as pool:
        futures = {pool.submit(fn): key for key, fn in tasks.items()}
        for fut in as_completed(futures):
            key = futures[fut]
            try:
                result = fut.result()
            except Exception:
                continue  # silent-fail per source
            if key == "loops":
                ev.update(result)  # expands to loops_stale + loops_activo
            else:
                ev[key] = result
    return ev


def _pendientes_extract_loops_fast(
    vault: Path, days: int = 14, max_items: int = 40,
) -> list[dict]:
    """Walk vault for notes modified in last `days`, extract loops via
    `_extract_followup_loops`, attach age_days. No LLM. Silent-fail per note.
    """
    if not vault.is_dir():
        return []
    now = datetime.now()
    start = now - timedelta(days=days)
    out: list[dict] = []
    for p in vault.rglob("*.md"):
        try:
            rel = str(p.relative_to(vault))
        except ValueError:
            continue
        if is_excluded(rel):
            continue
        try:
            st = p.stat()
        except OSError:
            continue
        mtime = st.st_mtime
        if datetime.fromtimestamp(mtime) < start:
            continue
        try:
            raw = p.read_text(encoding="utf-8", errors="ignore")
        except OSError:
            continue
        extracted_ts = _note_created_ts(raw, mtime)
        loops = _extract_followup_loops(raw, rel, extracted_ts)
        for loop in loops:
            try:
                ex_dt = datetime.fromisoformat(loop.get("extracted_at", ""))
                age_days = max(0, (now - ex_dt).days)
            except Exception:
                age_days = 0
            loop["age_days"] = age_days
            out.append(loop)
        if len(out) >= max_items * 3:
            break
    return out


def _pendientes_recent_contradictions(
    log_path: Path, now: datetime, days: int = 14, max_items: int = 5,
) -> list[dict]:
    """Index-time contradictions from the last `days`. Newest-first.

    Reads from rag_contradictions (SQL-only since T10). The `log_path` arg
    is retained for call-site compatibility but no longer consulted. On SQL
    error: empty list.
    """
    cutoff = now - timedelta(days=days)
    cutoff_iso = cutoff.isoformat(timespec="seconds")
    out: list[dict] = []

    try:
        with _ragvec_state_conn() as conn:
            rows = _sql_query_window(conn, "rag_contradictions", cutoff_iso)
    except Exception as exc:
        _log_sql_state_error("contradictions_sql_read_failed",
                              err=repr(exc))
        return []

    # Newest-first: rows come ordered by ts ASC; reverse.
    for r in reversed(rows):
        try:
            contradicts = json.loads(r["contradicts_json"]) \
                if r["contradicts_json"] else []
        except Exception:
            contradicts = []
        if not contradicts:
            continue
        out.append({
            "subject_path": r["subject_path"] or "",
            "targets": contradicts[:3],
            "ts": r["ts"],
        })
        if len(out) >= max_items:
            break
    return out


def _pendientes_low_conf_queries(
    log_path: Path, now: datetime, days: int = 7, max_items: int = 5,
) -> list[dict]:
    """Queries below `CONFIDENCE_RERANK_MIN` in last `days`. Dedup by q
    (keep lowest score). Sorted ascending.
    """
    if not log_path.is_file():
        return []
    cutoff = now - timedelta(days=days)
    best: dict[str, float] = {}
    try:
        lines = log_path.read_text(encoding="utf-8").splitlines()
    except OSError:
        return []
    for line in lines:
        line = line.strip()
        if not line:
            continue
        try:
            e = json.loads(line)
        except Exception:
            continue
        if e.get("cmd") != "query":
            continue
        try:
            ts = datetime.fromisoformat(e.get("ts", ""))
        except Exception:
            continue
        if ts < cutoff:
            continue
        score = e.get("top_score")
        if not isinstance(score, (int, float)) or score > CONFIDENCE_RERANK_MIN:
            continue
        q = (e.get("q") or "").strip()
        if not q:
            continue
        if q not in best or score < best[q]:
            best[q] = float(score)
    ranked = sorted(best.items(), key=lambda x: x[1])[:max_items]
    return [{"q": q, "top_score": s} for q, s in ranked]


def _pendientes_urgent(ev: dict, now: datetime) -> list[str]:
    """Surface items that jump off the screen — miss them = blown SLA."""
    urgent: list[str] = []
    for r in ev.get("reminders") or []:
        if r.get("bucket") == "overdue":
            lst = f" [{r['list']}]" if r.get("list") else ""
            urgent.append(f"⏰ overdue · {r.get('name','')}{lst}")
    for m in (ev.get("gmail") or {}).get("awaiting_reply") or []:
        if (m.get("days_old") or 0) >= 7:
            who = _format_gmail_from(m.get("from") or "")
            urgent.append(
                f"⏳ {m.get('days_old')}d · {m.get('subject','')} — {who}"
            )
    for m in ev.get("mail_unread") or []:
        if m.get("is_vip"):
            urgent.append(f"📧 VIP · {m.get('subject','')} — {m.get('sender','')}")
    return urgent


@cli.command("pendientes")
@click.option("--days", default=14, show_default=True,
              help="Ventana para loops/queries/contradicciones")
@click.option("--plain", is_flag=True, help="Salida plana (para bots)")
def pendientes(days: int, plain: bool):
    """Dashboard unificado: todo lo que espera tu atención ahora mismo.

    Gmail awaiting-reply + WhatsApp chats activos + Apple Reminders
    (overdue/today/undated) + loops del vault + contradicciones recientes +
    queries sin respuesta + agenda del día. Mid-day check-in: morning brief
    cubre el arranque, pendientes te reubica.

    Sin LLM, <3s en warm caches. Secciones vacías se omiten.
    """
    col = get_db()
    now = datetime.now()
    t0 = time.perf_counter()
    ev = _pendientes_collect(col, now, days=days)
    urgent = _pendientes_urgent(ev, now)

    log_query_event({
        "cmd": "pendientes", "days": days,
        "counts": {
            "urgent": len(urgent),
            "mail_unread": len(ev.get("mail_unread") or []),
            "gmail_awaiting": len((ev.get("gmail") or {}).get("awaiting_reply") or []),
            "whatsapp": len(ev.get("whatsapp") or []),
            "reminders": len(ev.get("reminders") or []),
            "loops_stale": len(ev.get("loops_stale") or []),
            "loops_activo": len(ev.get("loops_activo") or []),
            "contradictions": len(ev.get("contradictions") or []),
            "low_conf": len(ev.get("low_conf") or []),
            "calendar": len(ev.get("calendar") or []),
        },
        "timing": _round_timing_ms({"total_ms": (time.perf_counter() - t0) * 1000}),
    })

    if plain:
        _pendientes_render_plain(ev, urgent, now)
        return
    _pendientes_render_rich(ev, urgent, now)


def _pendientes_render_plain(ev: dict, urgent: list[str], now: datetime) -> None:
    out: list[str] = [f"📋 Pendientes · {now.strftime('%Y-%m-%d %H:%M')}"]
    if urgent:
        out.append("")
        out.append(f"🚨 Urgente ({len(urgent)})")
        out.extend(f"  {line}" for line in urgent)
    gm = ev.get("gmail") or {}
    awaiting = gm.get("awaiting_reply") or []
    if awaiting or gm.get("unread_count"):
        out.append("")
        out.append(f"📧 Gmail ({len(awaiting)} awaiting · {gm.get('unread_count',0)} unread)")
        for m in awaiting[:5]:
            who = _format_gmail_from(m.get("from") or "")
            out.append(f"  ⏳ {m.get('days_old',0)}d · {m.get('subject','')} — {who}")
    mail = ev.get("mail_unread") or []
    if mail:
        out.append("")
        out.append(f"📬 Apple Mail ({len(mail)} no leídos 36h)")
        for m in mail[:5]:
            prefix = "VIP · " if m.get("is_vip") else ""
            out.append(f"  · {prefix}{m.get('subject','')} — {m.get('sender','')}")
    wa = ev.get("whatsapp") or []
    if wa:
        out.append("")
        total = sum(int(w.get("count", 0)) for w in wa)
        out.append(f"💬 WhatsApp ({len(wa)} chats · {total} msgs 24h)")
        for w in wa[:5]:
            snip = (w.get("last_snippet") or "").strip()[:60]
            snip_part = f" — \"{snip}\"" if snip else ""
            out.append(f"  · {w.get('name','(?)')} ({w.get('count',0)}){snip_part}")
    rem = ev.get("reminders") or []
    if rem:
        out.append("")
        out.append(f"📌 Reminders ({len(rem)})")
        for bucket in ("overdue", "today", "upcoming", "undated"):
            for r in [x for x in rem if (x.get("bucket") or "") == bucket][:5]:
                lst = f" [{r['list']}]" if r.get("list") else ""
                due = f" · {r['due']}" if r.get("due") else ""
                tag = f"({bucket}) " if bucket != "undated" else "📌 "
                out.append(f"  {tag}{r.get('name','')}{due}{lst}")
    stale = ev.get("loops_stale") or []
    activo = ev.get("loops_activo") or []
    if stale or activo:
        out.append("")
        out.append(f"📁 Vault loops ({len(stale)} stale · {len(activo)} activo)")
        for it in stale[:3]:
            out.append(f"  🕸 {it.get('age_days',0)}d · {it.get('loop_text','')[:80]} [[{Path(it['source_note']).stem}]]")
        for it in activo[:3]:
            out.append(f"  🔥 {it.get('age_days',0)}d · {it.get('loop_text','')[:80]} [[{Path(it['source_note']).stem}]]")
    contrad = ev.get("contradictions") or []
    if contrad:
        out.append("")
        out.append(f"⚠ Contradicciones recientes ({len(contrad)})")
        for c in contrad[:3]:
            tgt = ", ".join(t.get("path","") for t in c.get("targets", [])[:2])
            out.append(f"  · {c.get('subject_path','')} ↔ {tgt}")
    low = ev.get("low_conf") or []
    if low:
        out.append("")
        out.append(f"❓ Queries sin respuesta ({len(low)})")
        for q in low[:3]:
            out.append(f"  · \"{q['q']}\" (score {q['top_score']:+.2f})")
    cal = ev.get("calendar") or []
    if cal:
        out.append("")
        out.append(f"📅 Hoy en agenda ({len(cal)})")
        for e in cal[:8]:
            out.append(f"  · {e.get('start','')} {e.get('title','')}")
    weather = ev.get("weather")
    if weather:
        out.append("")
        out.append(f"🌧 {weather.get('summary', 'lluvia')}")
    total_items = (
        len(urgent) + len(awaiting) + len(mail) + len(wa) + len(rem)
        + len(stale) + len(activo) + len(contrad) + len(low) + len(cal)
    )
    if total_items == 0:
        out.append("")
        out.append("✨ Todo limpio — sin pendientes trackeados.")
    click.echo("\n".join(out))


